INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 1, 'PABLO, siervo de Jesucristo, llamado á ser apóstol, apartado para el evangelio de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 2, 'Que él había antes prometido por sus profetas en las santas Escrituras,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 3, 'Acerca de su Hijo, (que fué hecho de la simiente de David según la carne;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 4, 'El cual fué declarado Hijo de Dios con potencia, según el espíritu de santidad, por la resurrección de los muertos), de Jesucristo Señor nuestro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 5, 'Por el cual recibimos la gracia y el apostolado, para la obediencia de la fe en todas las naciones en su nombre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 6, 'Entre las cuales sois también vosotros, llamados de Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 7, 'A todos los que estáis en Roma, amados de Dios, llamados santos: Gracia y paz tengáis de Dios nuestro Padre, y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 8, 'Primeramente, doy gracias á mi Dios por Jesucristo acerca de todos vosotros, de que vuestra fe es predicada en todo el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 9, 'Porque testigo me es Dios, al cual sirvo en mi espíritu en el evangelio de su Hijo, que sin cesar me acuerdo de vosotros siempre en mis oraciones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 10, 'Rogando, si al fin algún tiempo haya de tener, por la voluntad de Dios, próspero viaje para ir á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 11, 'Porque os deseo ver, para repartir con vosotros algún don espiritual, para confirmaros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 12, 'Es á saber, para ser juntamente consolado con vosotros por la común fe vuestra y juntamente mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 13, 'Mas no quiero, hermanos, que ingnoréis que muchas veces me he propuesto ir á vosotros (empero hasta ahora he sido estorbado), para tener también entre vosotros algún fruto, como entre los demás Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 14, 'A Griegos y á bárbaros, á sabios y á no sabios soy deudor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 15, 'Así que, cuanto á mí, presto estoy á anunciar el evangelio también á vosotros que estáis en Roma.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 16, 'Porque no me avergüenzo del evangelio: porque es potencia de Dios para salud á todo aquel que cree; al Judío primeramente y también al Griego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 17, 'Porque en él la justicia de Dios se descubre de fe en fe; como está escrito: Mas el justo vivirá por la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 18, 'Porque manifiesta es la ira de Dios del cielo contra toda impiedad é injusticia de los hombres, que detienen la verdad con injusticia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 19, 'Porque lo que de Dios se conoce, á ellos es manifiesto; porque Dios se lo manifestó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 20, 'Porque las cosas invisibles de él, su eterna potencia y divinidad, se echan de ver desde la creación del mundo, siendo entendidas por las cosas que son hechas; de modo que son inexcusables:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 21, 'Porque habiendo conocido á Dios, no le glorificaron como á Dios, ni dieron gracias; antes se desvanecieron en sus discursos, y el necio corazón de ellos fué entenebrecido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 22, 'Diciéndose ser sabios, se hicieron fatuos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 23, 'Y trocaron la gloria del Dios incorruptible en semejanza de imagen de hombre corruptible, y de aves, y de animales de cuatro pies, y de serpientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 24, 'Por lo cual también Dios los entregó á inmundicia, en las concupiscencias de sus corazones, de suerte que contaminaron sus cuerpos entre sí mismos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 25, 'Los cuales mudaron la verdad de Dios en mentira, honrando y sirviendo á las criaturas antes que al Criador, el cual es bendito por los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 26, 'Por esto Dios los entregó á afectos vergonzosos; pues aun sus mujeres mudaron el natural uso en el uso que es contra naturaleza:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 27, 'Y del mismo modo también los hombres, dejando el uso natural de las mujeres, se encendieron en sus concupiscencias los unos con los otros, cometiendo cosas nefandas hombres con hombres, y recibiendo en sí mismos la recompensa que convino á su extravío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 28, 'Y como á ellos no les pareció tener á Dios en su noticia, Dios los entregó á una mente depravada, para hacer lo que no conviene,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 29, 'Estando atestados de toda iniquidad, de fornicación, de malicia, de avaricia, de maldad; llenos de envidia, de homicidios, de contiendas, de engaños, de malignidades;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 30, 'Murmuradores, detractores, aborrecedores de Dios, injuriosos, soberbios, altivos, inventores de males, desobedientes á los padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 31, 'Necios, desleales, sin afecto natural, implacables, sin misericordia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 1, 32, 'Que habiendo entendido el juicio de Dios que los que hacen tales cosas son dignos de muerte, no sólo las hacen, más aún consienten á los que las hacen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 1, 'POR lo cual eres inexcusable, oh hombre, cuaquiera que juzgas: porque en lo que juzgas á otro, te condenas á ti mismo; porque lo mismo haces, tú que juzgas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 2, 'Mas sabemos que el juicio de Dios es según verdad contra los que hacen tales cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 3, '¿Y piensas esto, oh hombre, que juzgas á los que hacen tales cosas, y haces las mismas, que tú escaparás del juicio de Dios.?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 4, '¿O menosprecias las riquezas de su benignidad, y fhfifhfi ignorando que su benignidad te guía á arrepentimiento?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 5, 'Mas por tu dureza, y por tu corazón no arrepentido, atesoras para ti mismo ira para el día de la ira y de la manifestación del justo juicio de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 6, 'El cual pagará á cada uno conforme á sus obras:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 7, 'A los que perseverando en bien hacer, buscan gloria y honra e inmortalidad, la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 8, 'Mas á los que son contenciosos, y no obedecen á la verdad, antes obedecen á la injusticia, enojo é ira;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 9, 'Tribulación y angustia sobre toda persona humana que obra lo malo, el Judío primeramente, y también el Griego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 10, 'Mas gloria y honra y paz á cualquiera que obra el bien, al Judío primeramente, y también al Griego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 11, 'Porque no hay acepción de personas para con Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 12, 'Porque todos lo que sin ley pecaron, sin ley también perecerán; y todos los que en la ley pecaron, por la ley serán juzgados:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 13, 'Porque no los oidores de la ley son justos para con Dios, mas los hacedores de la ley serán justificados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 14, 'Porque los Gentiles que no tienen ley, naturalmente haciendo lo que es de la ley, los tales, aunque no tengan ley, ellos son ley á sí mismos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 15, 'Mostrando la obra de la ley escrita en sus corazones, dando testimonio juntamente sus conciencias, y acusándose y también excusándose sus pensamientos unos con otros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 16, 'En el día que juzgará el Señor lo encubierto de los hombres, conforme á mi evangelio, por Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 17, 'He aquí, tú tienes el sobrenombre de Judío, y estás reposado en la ley, y te glorías en Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 18, 'Y sabes su voluntad, y apruebas lo mejor, instruído por la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 19, 'Y confías que eres guía de los ciegos, luz de los que están en tinieblas,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 20, 'Enseñador de los que no saben, maestro de niños, que tienes la forma de la ciencia y de la verdad en la ley:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 21, 'Tú pues, que enseñas á otro, ¿no te enseñas á ti mismo? ¿Tú, que predicas que no se ha de hurtar, hurtas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 22, '¿Tú, que dices que no se ha de adulterar, adulteras? ¿Tú, que abominas los ídolos, cometes sacrilegio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 23, '¿Tú, que te jactas de la ley, con infracción de la ley deshonras á Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 24, 'Porque el nombre de Dios es blasfemado por causa de vosotros entre los Gentiles, como está esctrito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 25, 'Porque la circuncisión en verdad aprovecha, si guardares la ley; mas si eres rebelde á la ley, tu circuncisión es hecha incircuncisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 26, 'De manera que, si el incircunciso guardare las justicias de la ley, ¿no será tenida su incircuncisión por circuncisión?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 27, 'Y lo que de su natural es incircunciso, guardando perfectamente la ley, te juzgará á ti, que con la letra y con la circuncisión eres rebelde á la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 28, 'Porque no es Judío el que lo es en manifiesto; ni la circuncisión es la que es en manifiesto en la carne:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 2, 29, 'Mas es Judío el que lo es en lo interior; y la circuncisión es la del corazón, en espíritu, no en letra; la alabanza del cual no es de los hombres, sino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 1, '¿QUÉ, pues, tiene más el Judío? ¿ó qué aprovecha la circuncisión?,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 2, 'Mucho en todas maneras. Lo primero ciertamente, que la palabra de Dios les ha sido confiada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 3, '¿Pues qué si algunos de ellos han sido incrédulos? ¿la incredulidad de ellos habrá hecho vana la verdad de Dios?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 4, 'En ninguna manera; antes bien sea Dios verdadero, mas todo hombre mentiroso; como está escrito: Para que seas justificado en tus dichos, Y venzas cuando de ti se juzgare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 5, 'Y si nuestra iniquidad encarece la justicia de Dios, ¿qué diremos? ¿Será injusto Dios que da castigo? (hablo como hombre.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 6, 'En ninguna manera: de otra suerte ¿cómo juzgaría Dios el mundo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 7, 'Empero si la verdad de Dios por mi mentira creció á gloria suya, ¿por qué aun así yo soy juzgado como pecador?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 8, '¿Y por qué no decir (como somos blasfemados, y como algunos dicen que nosotros decimos): Hagamos males para que vengan bienes? la condenación de los cuales es justa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 9, '¿Qué pues? ¿Somos mejores que ellos? En ninguna manera: porque ya hemos acusado á Judíos y á Gentiles, que todos están debajo de pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 10, 'Como está escrito: No hay justo, ni aun uno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 11, 'No hay quien entienda, No hay quien busque á Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 12, 'Todos se apartaron, á una fueron hechos inútiles; No hay quien haga lo bueno, no hay ni aun uno:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 13, 'Sepulcro abierto es su garganta; Con sus lenguas tratan engañosamente; Veneno de áspides está debajo de sus labios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 14, 'Cuya boca está llena de maledicencia y de amargura;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 15, 'Sus pies son ligeros á derramar sangre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 16, 'Quebrantamiento y desventura hay en sus caminos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 17, 'Y camino de paz no conocieron:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 18, 'No hay temor de Dios delante de sus ojos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 19, 'Empero sabemos que todo lo que la ley dice, á los que están en la ley lo dice, para que toda boca se tape, y que todo el mundo se sujete á Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 20, 'Porque por las obras de la ley ninguna carne se justificará delante de él; porque por la ley es el conocimiento del pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 21, 'Mas ahora, sin la ley, la justicia de Dios se ha manifestado, testificada por la ley y por los profetas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 22, 'La justicia de Dios por la fe de Jesucristo, para todos los que creen en él: porque no hay diferencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 23, 'Por cuanto todos pecaron, y están distituídos de la gloria de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 24, 'Siendo justificados gratuitamente por su gracia por la redención que es en Cristo Jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 25, 'Al cual Dios ha propuesto en propiciación por la fe en su sangre, para manifestación de su justicia, atento á haber pasado por alto, en su paciencia, los pecados pasados,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 26, 'Con la mira de manifestar su justicia en este tiempo: para que él sea el justo, y el que justifica al que es de la fe de Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 27, '¿Dondé pues está la jactancia? Es excluída. ¿Por cuál ley? ¿de las obras? No; mas por la ley de la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 28, 'Así que, concluímos ser el hombre justificado por fe sin las obras de la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 29, '¿Es Dios solamente Dios de los Judíos? ¿No es también Dios de los Gentiles? Cierto, también de los Gentiles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 30, 'Porque uno es Dios, el cual justificará por la fe la circuncisión, y por medio de la fe la incircuncisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 3, 31, '¿Luego deshacemos la ley por la fe? En ninguna manera; antes establecemos la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 1, '¿QUÉ, pues, diremos que halló Abraham nuestro padre según la carne?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 2, 'Que si Abraham fué justificado por la obras, tiene de qué gloriarse; mas no para con Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 3, 'Porque ¿qué dice la Escritura? Y creyó Abraham á Dios, y le fué atribuído á justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 4, 'Empero al que obra, no se le cuenta el salario por merced, sino por deuda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 5, 'Mas al que no obra, pero cree en aquél que justifica al impío, la fe le es contada por justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 6, 'Como también David dice ser bienaventurado el hombre al cual Dios atribuye justicia sin obras,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 7, 'Diciendo: Bienaventurados aquellos cuyas iniquidades son perdonadas, Y cuyos pecados son cubiertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 8, 'Bienaventurado el varón al cual el Señor no imputó pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 9, '¿Es pues esta bienaventuranza solamente en la circuncisión ó también en la incircuncisión? porque decimos que á Abraham fué contada la fe por justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 10, '¿Cómo pues le fué contada? ¿en la circuncisión, ó en la incircuncisión? No en la circuncisión, sino en la incircuncisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 11, 'Y recibió la circuncisión por señal, por sello de la justicia de la fe que tuvo en la incircuncisión: para que fuese padre de todos los creyentes no circuncidados, para que también á ellos les sea contado por justicia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 12, 'Y padre de la circuncisión, no solamente á los que son de la circuncisión, más también á los que siguen las pisadas de la fe que fué en nuestro padre Abraham antes de ser circuncidado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 13, 'Porque no por la ley fué dada la promesa á Abraham ó á su simiente, que sería heredero del mundo, sino por la justicia de la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 14, 'Porque si los que son de la ley son los herederos, vana es la fe, y anulada es la promesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 15, 'Porque la ley obra ira; porque donde no hay ley, tampoco hay transgresión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 16, 'Por tanto es por la fe, para que sea por gracia; para que la promesa sea firme á toda simiente, no solamente al que es de la ley, mas también al que es de la fe de Abraham, el cual es padre de todos nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 17, '(Como está escrito: Que por padre de muchas gentes te he puesto) delante de Dios, al cual creyó; el cual da vida á los muertos, y llama las cosas que no son, como las que son.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 18, 'El creyó en esperanza contra esperanza, para venir á ser padre de muchas gentes, conforme á lo que le había sido dicho: Así será tu simiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 19, 'Y no se enflaqueció en la fe, ni consideró su cuerpo ya muerto (siendo ya de casi cien años,) ni la matriz muerta de Sara;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 20, 'Tampoco en la promesa de Dios dudó con desconfianza: antes fué esforzado en fe, dando gloria á Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 21, 'Plenamente convencido de que todo lo que había prometido, era también poderoso para hacerlo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 22, 'Por lo cual también le fué atribuído á justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 23, 'Y no solamente por él fué escrito que le haya sido imputado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 24, 'Sino también por nosotros, á quienes será imputado, esto es, á los que creemos en el que levantó de los muertos á Jesús Señor nuestro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 4, 25, 'El cual fué entregado por nuestros delitos, y resucitado para nuestra justificación');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 1, 'JUSTIFICADOS pues por la fe, tenemos paz para con Dios por medio de nuestro Señor Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 2, 'Por el cual también tenemos entrada por la fe á esta gracia en la cual estamos firmes, y nos gloriamos en la esperanza de la gloria de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 3, 'Y no sólo esto, mas aun nos gloriamos en las tribulaciones, sabiendo que la tribulación produce paciencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 4, 'Y la paciencia, prueba; y la prueba, esperanza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 5, 'Y la esperanza no avergüenza; porque el amor de Dios está derramado en nuestros corazones por el Espíritu Santo que nos es dado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 6, 'Porque Cristo, cuando aún éramos flacos, á su tiempo murió por los impíos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 7, 'Ciertamente apenas muere algun por un justo: con todo podrá ser que alguno osara morir por el bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 8, 'Mas Dios encarece su caridad para con nosotros, porque siendo aún pecadores, Cristo murió por nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 9, 'Luego mucho más ahora, justificados en su sangre, por él seremos salvos de la ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 10, 'Porque si siendo enemigos, fuimos reconciliado con Dios por la muerte de su Hijo, mucho más, estando reconciliados, seremos salvos por su vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 11, 'Y no sólo esto, mas aun nos gloriamos en Dios por el Señor nuestro Jesucristo, por el cual hemos ahora recibido la reconciliación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 12, 'De consiguiente, vino la reconciliación por uno, así como el pecado entró en el mundo por un hombre, y por el pecado la muerte, y la muerte así pasó á todos los hombres, pues que todos pecaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 13, 'Porque hasta la ley, el pecado estaba en el mundo; pero no se imputa pecado no habiendo ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 14, 'No obstante, reinó la muerte desde Adam hasta Moisés, aun en los que no pecaron á la manera de la rebelión de Adam; el cual es figura del que había de venir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 15, 'Mas no como el delito, tal fué el don: porque si por el delito de aquel uno murieron los muchos, mucho más abundó la gracia de Dios á los muchos, y el don por la gracia de un hombre, Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 16, 'Ni tampoco de la manera que por un pecado, así también el don: porque el juicio á la verdad vino de un pecado para condenación, mas la gracia vino de muchos delitos para justificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 17, 'Porque, si por un delito reinó la muerte por uno, mucho más reinarán en vida por un Jesucristo los que reciben la abundancia de gracia, y del don de la justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 18, 'Así que, de la manera que por un delito vino la culpa á todos los hombres para condenación, así por una justicia vino la gracia á todos los hombres para justificación de vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 19, 'Porque como por la desobediencia de un hombre los muchos fueron constituídos pecadores, así por la obediencia de uno los muchos serán constituídos justos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 20, 'La ley empero entró para que el pecado creciese; mas cuando el pecado creció, sobrepujó la gracia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 5, 21, 'Para que, de la manera que el pecado reinó para muerte, así también la gracia reine por la justicia para vida eterna por Jesucristo Señor nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 1, '¿PUES qué diremos? Perseveraremos en pecado para que la gracia crezca?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 2, 'En ninguna manera. Porque los que somos muertos al pecado, ¿cómo viviremos aún en él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 3, '¿O no sabéis que todos los que somos bautizados en Cristo Jesús, somos bautizados en su muerte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 4, 'Porque somos sepultados juntamente con él á muerte por el bautismo; para que como Cristo resucitó de los muertos por la gloria del Padre, así también nosotros andemos en novedad de vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 5, 'Porque si fuimos plantados juntamente en él á la semejanza de su muerte, así también lo seremos á la de su resurrección:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 6, 'Sabiendo esto, que nuestro viejo hombre juntamente fué crucificado con él, para que el cuerpo del pecado sea deshecho, á fin de que no sirvamos más al pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 7, 'Porque el que es muerto, justificado es del pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 8, 'Y si morimos con Cristo, creemos que también viviremos con él;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 9, 'Sabiendo que Cristo, habiendo resucitado de entre los muertos, ya no muere: la muerte no se enseñoreará más de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 10, 'Porque el haber muerto, al pecado murió una vez; mas el vivir, á Dios vive.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 11, 'Así también vosotros, pensad que de cierto estáis muertos al pecado, mas vivos á Dios en Cristo Jesús Señor nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 12, 'No reine, pues, el pecado en vuestro cuerpo mortal, para que le obedezcáis en sus concupiscencias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 13, 'Ni tampoco presentéis vuestros miembros al pecado por instrumento de iniquidad; antes presentaos á Dios como vivos de los muertos, y vuestros miembros á Dios por instrumentos de justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 14, 'Porque el pecado no se enseñoreará de vosotros; pues no estáis bajo la ley, sino bajo la gracia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 15, '¿Pues qué? ¿Pecaremos, porque no estamos bajo de la ley, sino bajo de la gracia? En ninguna manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 16, '¿No sabéis que á quien os prestáis vosotros mismos por siervos para obedecer le, sois siervos de aquel á quien obedecéis, ó del pecado para muerte, ó de la obediencia para justicia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 17, 'Empero gracias á Dios, que aunque fuistes siervos del pecado, habéis obedecido de corazón á aquella forma de doctrina á la cual sois entregados;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 18, 'Y libertados del pecado, sois hechos siervos de la justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 19, 'Humana cosa digo, por la flaqueza de vuestra carne: que como para iniquidad presentasteis vuestros miembros á servir á la inmundicia y á la iniquidad, así ahora para santidad presentéis vuestros miembros á servir á la justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 20, 'Porque cuando fuisteis siervos del pecado, erais libres acerca de la justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 21, '¿Qué fruto, pues, teníais de aquellas cosas de las cuales ahora os avergonzáis? porque el fin de ellas es muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 22, 'Mas ahora, librados del pecado, y hechos siervos á Dios, tenéis por vuestro fruto la santificación, y por fin la vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 6, 23, 'Porque la paga del pecado es muerte: mas la dádiva de Dios es vida eterna en Cristo Jesús Señor nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 1, '¿IGNORAIS, hermanos, (porque hablo con los que saben la ley) que la ley se enseñorea del hombre entre tanto que vive?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 2, 'Porque la mujer que está sujeta á marido, mientras el marido vive está obligada á la ley; mas muerto el marido, libre es de la ley del marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 3, 'Así que, viviendo el marido, se llamará adúltera si fuere de otro varón; mas si su marido muriere, es libre de la ley; de tal manera que no será adúltera si fuere de otro marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 4, 'Así también vosotros, hermanos míos, estáis muertos á la ley por el cuerpo de Cristo, para que seáis de otro, á saber, del que resucitó de los muertos, á fin de que fructifiquemos á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 5, 'Porque mientras estábamos en la carne, los afectos de los pecados que eran por la ley, obraban en nuestros miembros fructificando para muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 6, 'Mas ahora estamos libres de la ley, habiendo muerto á aquella en la cual estábamos detenidos, para que sirvamos en novedad de espíritu, y no en vejez de letra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 7, '¿Qué pues diremos? ¿La ley es pecado? En ninguna manera. Empero yo no conocí el pecado sino por la ley: porque tampoco conociera la concupiscencia, si la ley no dijera: No codiciarás.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 8, 'Mas el pecado, tomando ocasión, obró en mí por el mandamiento toda concupiscencia: porque sin la ley el pecado está muerto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 9, 'Así que, yo sin la ley vivía por algún tiempo: mas venido el mandamiento, el pecado revivió, y yo morí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 10, 'Y hallé que el mandamiento, á intimado para vida, para mí era mortal:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 11, 'Porque el pecado, tomando ocasión, me engañó por el mandamiento, y por él me mató.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 12, 'De manera que la ley á la verdad es santa, y el mandamiento santo, y justo, y bueno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 13, '¿Luego lo que es bueno, á mí me es hecho muerte? No; sino que el pecado, para mostrarse pecado, por lo bueno me obró la muerte, haciéndose pecado sobremanera pecante por el mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 14, 'Porque sabemos que la ley es espiritual; mas yo soy carnal, vendido á sujeción del pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 15, 'Porque lo que hago, no lo entiendo; ni lo que quiero, hago; antes lo que aborrezco, aquello hago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 16, 'Y si lo que no quiero, esto hago, apruebo que la ley es buena.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 17, 'De manera que ya no obro aquello, sino el pecado que mora en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 18, 'Y yo sé que en mí (es á saber, en mi carne) no mora el bien: porque tengo el querer, mas efectuar el bien no lo alcanzo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 19, 'Porque no hago el bien que quiero; mas el mal que no quiero, éste hago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 20, 'Y si hago lo que no quiero, ya no obro yo, sino el mal que mora en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 21, 'Así que, queriendo yo hacer el bien, hallo esta ley: Que el mal está en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 22, 'Porque según el hombre interior, me deleito en la ley de Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 23, 'Mas veo otra ley en mis miembros, que se rebela contra la ley de mi espíritu, y que me lleva cautivo á la ley del pecado que está en mis miembros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 24, '¡Miserable hombre de mí! ¿quién me librará del cuerpo de esta muerte?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 7, 25, 'Gracias doy á Dios, por Jesucristo Señor nuestro. Así que, yo mismo con la mente sirvo á la ley de Dios, mas con la carne á la ley del pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 1, 'AHORA pues, ninguna condenación hay para los que están en Cristo Jesús, los que no andan conforme á la carne, mas conforme al espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 2, 'Porque la ley del Espíritu de vida en Cristo Jesús me ha librado de la ley del pecado y de la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 3, 'Porque lo que era imposible á la ley, por cuanto era débil por la carne, Dios enviando á su Hijo en semejanza de carne de pecado, y á causa del pecado, condenó al pecado en la carne;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 4, 'Para que la justicia de la ley fuese cumplida en nosotros, que no andamos conforme á la carne, mas conforme al espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 5, 'Porque los que viven conforme á la carne, de las cosas que son de la carne se ocupan; mas los que conforme al espíritu, de las cosas del espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 6, 'Porque la intención de la carne es muerte; mas la intención del espíritu, vida y paz:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 7, 'Por cuanto la intención de la carne es enemistad contra Dios; porque no se sujeta á la ley de Dios, ni tampoco puede.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 8, 'Así que, los que están en la carne no pueden agradar á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 9, 'Mas vosotros no estáis en la carne, sino en el espíritu, si es que el Espíritu de Dios mora en vosotros. Y si alguno no tiene el Espíritu de Cristo, el tal no es de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 10, 'Empero si Cristo está en vosotros, el cuerpo á la verdad está muerto á causa del pecado; mas el espíritu vive á causa de la justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 11, 'Y si el Espíritu de aquel que levantó de los muertos á Jesús mora en vosotros, el que levantó á Cristo Jesús de los muertos, vivificará también vuestros cuerpos mortales por su Espíritu que mora en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 12, 'Así que, hermanos, deudores somos, no á la carne, para que vivamos conforme á la carne:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 13, 'Porque si viviereis conforme á la carne, moriréis; mas si por el espíritu mortificáis las obras de la carne, viviréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 14, 'Porque todos los que son guiados por el Espíritu de Dios, los tales son hijos de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 15, 'Porque no habéis recibido el espíritu de servidumbre para estar otra vez en temor; mas habéis recibido el espíritu de adopción, por el cual clamamos, Abba, Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 16, 'Porque el mismo Espíritu da testimonio á nuestro espíritu que somos hijos de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 17, 'Y si hijos, también herederos; herederos de Dios, y coherederos de Cristo; si empero padecemos juntamente con él, para que juntamente con él seamos glorificados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 18, 'Porque tengo por cierto que lo que en este tiempo se padece, no es de comparar con la gloria venidera que en nosotros ha de ser manifestada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 19, 'Porque el continuo anhelar de las criaturas espera la manifestación de los hijos de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 20, 'Porque las criaturas sujetas fueron á vanidad, no de grado, mas por causa del que las sujetó con esperanza,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 21, 'Que también las mismas criaturas serán libradas de la servidumbre de corrupción en la libertad gloriosa de los hijos de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 22, 'Porque sabemos que todas las criaturas gimen á una, y á una están de parto hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 23, 'Y no sólo ellas, mas también nosotros mismos, que tenemos las primicias del Espíritu, nosotros también gemimos dentro de nosotros mismos, esperando la adopción, es á saber, la redención de nuestro cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 24, 'Porque en esperanza somos salvos; mas la esperanza que se ve, no es esperanza; porque lo que alguno ve, ¿á qué esperarlo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 25, 'Empero si lo que no vemos esperamos, por paciencia esperamos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 26, 'Y asimismo también el Espíritu ayuda nuestra flaqueza: porque qué hemos de pedir como conviene, no lo sabemos; sino que el mismo Espíritu pide por nosotros con gemidos indecibles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 27, 'Mas el que escudriña los corazones, sabe cuál es el intento del Espíritu, porque conforme á la voluntad de Dios, demanda por los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 28, 'Y sabemos que á los que á Dios aman, todas las cosas les ayudan á bien, es á saber, á los que conforme al propósito son llamados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 29, 'Porque á los que antes conoció, también predestinó para que fuesen hechos conformes á la imagen de su Hijo, para que él sea el primogénito entre muchos hermanos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 30, 'Y á los que predestinó, á éstos también llamó; y á los que llamó, á éstos también justificó; y á los que justificó, á éstos también glorificó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 31, '¿Pues qué diremos á esto? Si Dios por nosotros, ¿quién contra nosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 32, 'El que aun á su propio Hijo no perdonó, antes le entregó por todos nosotros, ¿cómo no nos dará también con él todas las cosas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 33, '¿Quién acusará á los escogidos de Dios? Dios es el que justifica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 34, '¿Quién es el que condenará? Cristo es el que murió; más aún, el que también resucitó, quien además está á la diestra de Dios, el que también intercede por nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 35, '¿Quién nos apartará del amor de Cristo? tribulación? ó angustia? ó persecución? ó hambre? ó desnudez? ó peligro? ó cuchillo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 36, 'Como está escrito: Por causa de ti somos muertos todo el tiempo: Somos estimados como ovejas de matadero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 37, 'Antes, en todas estas cosas hacemos más que vencer por medio de aquel que nos amó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 38, 'Por lo cual estoy cierto que ni la muerte, ni la vida, ni ángeles, ni principados, ni potestades, ni lo presente, ni lo por venir,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 8, 39, 'Ni lo alto, ni lo bajo, ni ninguna criatura nos podrá apartar del amor de Dios, que es en Cristo Jesús Señor nuestro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 1, 'VERDAD digo en Cristo, no miento, dándome testimonio mi conciencia en el Espíritu Santo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 2, 'Que tengo gran tristeza y continuo dolor en mi corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 3, 'Porque deseara yo mismo ser apartado de Cristo por mis hermanos, los que son mis parientes según la carne;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 4, 'Que son israelitas, de los cuales es la adopción, y la gloria, y el pacto, y la data de la ley, y el culto, y las promesas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 5, 'Cuyos son los padres, y de los cuales es Cristo según la carne, el cual es Dios sobre todas las cosas, bendito por los siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 6, 'No empero que la palabra de Dios haya faltado: porque no todos los que son de Israel son Israelitas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 7, 'Ni por ser simiente de Abraham, son todos hijos; mas: En Isaac te será llamada simiente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 8, 'Quiere decir: No los que son hijos de la carne, éstos son los hijos de Dios; mas los que son hijos de la promesa, son contados en la generación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 9, 'Porque la palabra de la promesa es esta: Como en este tiempo vendré, y tendrá Sara un hijo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 10, 'Y no sólo esto; mas también Rebeca concibiendo de uno, de Isaac nuestro padre,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 11, '(Porque no siendo aún nacidos, ni habiendo hecho aún ni bien ni mal, para que el propósito de Dios conforme á la elección, no por las obras sino por el que llama, permaneciese;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 12, 'Le fué dicho que el mayor serviría al menor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 13, 'Como está escrito: A Jacob amé, mas á Esaú aborrecí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 14, '¿Pues qué diremos? ¿Que hay injusticia en Dios? En ninguna manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 15, 'Mas á Moisés dice: Tendré misericordia del que tendré misericordia, y me compadeceré del que me compadeceré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 16, 'Así que no es del que quiere, ni del que corre, sino de Dios que tiene misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 17, 'Porque la Escritura dice de Faraón: Que para esto mismo te he levantado, para mostrar en ti mi potencia, y que mi nombre sea anunciado por toda la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 18, 'De manera que del que quiere tiene misericordia; y al que quiere, endurece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 19, 'Me dirás pues: ¿Por qué, pues, se enoja? porque ¿quién resistirá á su voluntad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 20, 'Mas antes, oh hombre, ¿quién eres tú, para que alterques con Dios? Dirá el vaso de barro al que le labró: ¿Por qué me has hecho tal?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 21, '¿O no tiene potestad el alfarero para hacer de la misma masa un vaso para honra, y otro para vergüenza?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 22, '¿Y qué, si Dios, queriendo mostrar la ira y hacer notoria su potencia, soportó con mucha mansedumbre los vasos de ira preparados para muerte,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 23, 'Y para hacer notorias las riquezas de su gloria, mostrólas para con los vasos de misericordia que él ha preparado para gloria;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 24, 'Los cuales también ha llamado, es á saber, á nosotros, no sólo de los Judíos, mas también de los Gentiles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 25, 'Como también en Oseas dice: Llamaré al que no era mi pueblo, pueblo mío; Y á la no amada, amada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 26, 'Y será, que en el lugar donde les fué dicho: Vosotros no sois pueblo mío: Allí serán llamados hijos del Dios viviente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 27, 'También Isaías clama tocante á Israel: Si fuere el número de los hijos de Israel como la arena de la mar, las reliquias serán salvas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 28, 'Porque palabra consumadora y abreviadora en justicia, porque palabra abreviada, hará el Señor sobre la tierra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 29, 'Y como antes dijo Isaías: Si el Señor de los ejércitos no nos hubiera dejado simiente, Como Sodoma habríamos venido á ser, y á Gomorra fuéramos semejantes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 30, '¿Pues qué diremos? Que los Gentiles que no seguían justicia, han alcanzado la justicia, es á saber, la justicia que es por la fe;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 31, 'Mas Israel que seguía la ley de justicia, no ha llegado á la ley de justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 32, '¿Por qué? Porque la seguían no por fe, mas como por las obras de la ley: por lo cual tropezaron en la piedra de tropiezo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 9, 33, 'Como está escrito: He aquí pongo en Sión piedra de tropiezo, y piedra de caída; Y aquel que creyere en ella, no será avergonzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 1, 'HERMANOS, ciertamente la voluntad de mi corazón y mi oración á Dios sobre Israel, es para salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 2, 'Porque yo les doy testimonio que tienen celo de Dios, mas no conforme á ciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 3, 'Porque ignorando la justicia de Dios, y procurando establecer la suya propia, no se han sujetado á la justicia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 4, 'Porque el fin de la ley es Cristo, para justicia á todo aquel que cree.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 5, 'Porque Moisés describe la justicia que es por la ley: Que el hombre que hiciere estas cosas, vivirá por ellas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 6, 'Mas la justicia que es por la fe dice así: No digas en tu corazón: ¿Quién subirá al cielo? (esto es, para traer abajo á Cristo:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 7, 'O, ¿quién descenderá al abismo? (esto es, para volver á traer á Cristo de los muertos.)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 8, 'Mas ¿qué dice? Cercana está la palabra, en tu boca y en tu corazón. Esta es la palabra de fe, la cual predicamos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 9, 'Que si confesares con tu boca al Señor Jesús, y creyeres en tu corazón que Dios le levantó de los muertos, serás salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 10, 'Porque con el corazón se cree para justicia; mas con la boca se hace confesión para salud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 11, 'Porque la Escritura dice: Todo aquel que en él creyere, no será avergonzado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 12, 'Porque no hay diferencia de Judío y de Griego: porque el mismo que es Señor de todos, rico es para con todos los que le invocan:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 13, 'Porque todo aquel que invocare el nombre del Señor, será salvo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 14, '¿Cómo, pues invocarán á aquel en el cual no han creído? ¿y cómo creerán á aquel de quien no han oído? ¿y cómo oirán sin haber quien les predique?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 15, '¿Y cómo predicarán si no fueren enviados? Como está escrito: ¡Cuán hermosos son los pies de los que anuncian el evangelio de la paz, de los que anuncian el evangelio de los bienes!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 16, 'Mas no todos obedecen al evangelio; pues Isaías dice: Señor, ¿quién ha creído á nuestro anuncio?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 17, 'Luego la fe es por el oir; y el oir por la palabra de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 18, 'Mas digo: ¿No han oído? Antes bien, Por toda la tierra ha salido la fama de ellos, Y hasta los cabos de la redondez de la tierra las palabras de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 19, 'Mas digo: ¿No ha conocido esto Israel? Primeramente Moisés dice: Yo os provocaré á celos con gente que no es mía; Con gente insensata os provocaré á ira.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 20, 'E Isaías determinadamente dice: Fuí hallado de los que no me buscaban; Manifestéme á los que no preguntaban por mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 10, 21, 'Mas acerca de Israel dice: Todo el día extendí mis manos á un pueblo rebelde y contradictor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 1, 'DIGO pues: ¿Ha desechado Dios á su pueblo? En ninguna manera. Porque también yo soy Israelita, de la simiente de Abraham, de la tribu de Benjamín.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 2, 'No ha desechado Dios á su pueblo, al cual antes conoció. ¿O no sabéis qué dice de Elías la Escritura? cómo hablando con Dios contra Israel dice:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 3, 'Señor, á tus profetas han muerto, y tus altares han derruído; y yo he quedado solo, y procuran matarme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 4, 'Mas ¿qué le dice la divina respuesta? He dejado para mí siete mil hombres, que no han doblado la rodilla delante de Baal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 5, 'Así también, aun en este tiempo han quedado reliquias por la elección de gracia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 6, 'Y si por gracia, luego no por las obras; de otra manera la gracia ya no es gracia. Y si por las obras, ya no es gracia; de otra manera la obra ya no es obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 7, '¿Qué pues? Lo que buscaba Israel aquello no ha alcanzado; mas la elección lo ha alcanzado: y los demás fueron endurecidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 8, 'Como está escrito: Dióles Dios espíritu de remordimiento, ojos con que no vean, y oídos con que no oigan, hasta el día de hoy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 9, 'Y David dice: Séales vuelta su mesa en lazo, y en red, Y en tropezadero, y en paga:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 10, 'Sus ojos sean obscurecidos para que no vean, Y agóbiales siempre el espinazo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 11, 'Digo pues: ¿Han tropezado para que cayesen? En ninguna manera; mas por el tropiezo de ellos vino la salud á los Gentiles, para que fuesen provocados á celos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 12, 'Y si la falta de ellos es la riqueza del mundo, y el menoscabo de ellos la riqueza de los Gentiles, ¿cuánto más el henchimiento de ellos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 13, 'Porque á vosotros hablo, Gentiles. Por cuanto pues, yo soy apóstol de los Gentiles, mi ministerio honro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 14, 'Por si en alguna manera provocase á celos á mi carne, e hiciese salvos á algunos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 15, 'Porque si el extrañamiento de ellos es la reconciliación del mundo, ¿qué será el recibimiento de ellos, sino vida de los muertos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 16, 'Y si el primer fruto es santo, también lo es el todo, y si la raíz es santa, también lo son las ramas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 17, 'Que si algunas de las ramas fueron quebradas, y tú, siendo acebuche, has sido ingerido en lugar de ellas, y has sido hecho participante de la raíz y de la grosura de la oliva;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 18, 'No te jactes contra las ramas; y si te jactas, sabe que no sustentas tú á la raíz, sino la raíz á ti.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 19, 'Pues las ramas, dirás, fueron quebradas para que yo fuese ingerido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 20, 'Bien: por su incredulidad fueron quebradas, mas tú por la fe estás en pie. No te ensoberbezcas, antes teme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 21, 'Que si Dios no perdonó á las ramas naturales, á ti tampoco no perdone.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 22, 'Mira, pues, la bondad y la severidad de Dios: la severidad ciertamente en los que cayeron; mas la bondad para contigo, si permanecieres en la bondad; pues de otra manera tú también serás cortado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 23, 'Y aun ellos, si no permanecieren en incredulidad, serán ingeridos; que poderoso es Dios para volverlos á ingerir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 24, 'Porque si tú eres cortado del natural acebuche, y contra natura fuiste ingerido en la buena oliva, ¿cuánto más éstos, que son las ramas naturales, serán ingeridos en su oliva?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 25, 'Porque no quiero, hermanos, que ignoréis este misterio, para que no seáis acerca de vosotros mismos arrogantes: que el endurecimiento en parte ha acontecido en Israel, hasta que haya entrado la plenitud de los Gentiles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 26, 'Y luego todo Israel será salvo; como está escrito: Vendrá de Sión el Libertador, Que quitará de Jacob la impiedad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 27, 'Y este es mi pacto con ellos, Cuando quitare su pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 28, 'Así que, cuanto al evangelio, son enemigos por causa de vosotros: mas cuanto á la elección, son muy amados por causa de los padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 29, 'Porque sin arrepentimiento son las mercedes y la vocación de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 30, 'Porque como también vosotros en algún tiempo no creísteis á Dios, mas ahora habéis alcanzado misericordia por la incredulidad de ellos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 31, 'Así también éstos ahora no ha creído, para que, por la misericordia para con vosotros, ellos también alcancen misericordia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 32, 'Porque Dios encerró á todos en incredulidad, para tener misericordia de todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 33, '¡Oh profundidad de las riquezas de la sabiduría y de la ciencia de Dios! ¡Cuán incomprensibles son sus juicios, e inescrutables sus caminos!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 34, 'Porque ¿quién entendió la mente del Señor? ¿ó quién fué su consejero?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 35, '¿O quién le dió á él primero, para que le sea pagado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 11, 36, 'Porque de él, y por él, y en él, son todas las cosas. A él sea gloria por siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 1, 'ASI que, hermanos, os ruego por las misericordias de Dios, que presentéis vuestros cuerpos en sacrificio vivo, santo, agradable á Dios, que es vuestro racional culto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 2, 'Y no os conforméis á este siglo; mas reformaos por la renovación de vuestro entendimiento, para que experimentéis cuál sea la buena voluntad de Dios, agradable y perfecta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 3, 'Digo pues por la gracia que me es dada, á cada cual que está entre vosotros, que no tenga más alto concepto de sí que el que debe tener, sino que piense de sí con templanza, conforme á la medida de la fe que Dios repartió á cada uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 4, 'Porque de la manera que en un cuerpo tenemos muchos miembros, empero todos los miembros no tienen la misma operación;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 5, 'Así muchos somos un cuerpo en Cristo, mas todos miembros los unos de los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 6, 'De manera que, teniendo diferentes dones según la gracia que nos es dada, si el de profecía, úsese conforme á la medida de la fe;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 7, 'ó si ministerio, en servir; ó el que enseña, en doctrina;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 8, 'El que exhorta, en exhortar; el que reparte, hágalo en simplicidad; el que preside, con solicitud; el que hace misericordia, con alegría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 9, 'El amor sea sin fingimiento: aborreciendo lo malo, llegándoos á lo bueno;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 10, 'Amándoos los unos á los otros con caridad fraternal; previniéndoos con honra los unos á los otros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 11, 'En el cuidado no perezosos; ardientes en espíritu; sirviendo al Señor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 12, 'Gozosos en la esperanza; sufridos en la tribulación; constantes en la oración;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 13, 'Comunicando á las necesidades de los santos; siguiendo la hospitalidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 14, 'Bendecid á los que os persiguen: bendecid y no maldigáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 15, 'Gozaos con los que se gozan: llorad con los que lloran.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 16, 'Unánimes entre vosotros: no altivos, mas acomodándoos á los humildes. No seáis sabios en vuestra opinión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 17, 'No paguéis á nadie mal por mal; procurad lo bueno delante de todos los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 18, 'Si se puede hacer, cuanto está en vosotros, tened paz con todos los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 19, 'No os venguéis vosotros mismos, amados míos; antes dad lugar á la ira; porque escrito está: Mía es la venganza: yo pagaré, dice el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 20, 'Así que, si tu enemigo tuviere hambre, dale de comer; si tuviere sed, dale de beber: que haciendo esto, ascuas de fuego amontonas sobre su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 12, 21, 'No seas vencido de lo malo; mas vence con el bien el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 1, 'TODA alma se someta á las potestades superiores; porque no hay potestad sino de Dios; y las que son, de Dios son ordenadas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 2, 'Asi que, el que se opone á la potestad, á la ordenación de Dios resiste: y los que resisten, ellos mismos ganan condenación para sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 3, 'Porque los magistrados no son para temor al que bien hace, sino al malo. ¿Quieres pues no temer la potestad? haz lo bueno, y tendrás alabanza de ella;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 4, 'Porque es ministro de Dios para tu bien. Mas si hicieres lo malo, teme: porque no en vano lleva el cuchillo; porque es ministro de Dios, vengador para castigo al que hace lo malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 5, 'Por lo cual es necesario que le estéis sujetos, no solamente por la ira, mas aun por la conciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 6, 'Porque por esto pagáis también los tributos; porque son ministros de Dios que sirven á esto mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 7, 'Pagad á todos lo que debéis: al que tributo, tributo; al que pecho, pecho; al que temor, temor; al que honra, honra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 8, 'No debáis á nadie nada, sino amaros unos á otros; porque el que ama al prójimo, cumplió la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 9, 'Porque: No adulterarás; no matarás; no hurtarás; no dirás falso testimonio; no codiciarás: y si hay algún otro mandamiento, en esta sentencia se comprende sumariamente: Amarás á tu prójimo como á ti mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 10, 'La caridad no hace mal al prójimo: así que, el cumplimento de la ley es la caridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 11, 'Y esto, conociendo el tiempo, que es ya hora de levantarnos del sueño; porque ahora nos está más cerca nuestra salud que cuando creímos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 12, 'La noche ha pasado, y ha llegado el día: echemos, pues, las obras de las tinieblas, y vistámonos las armas de luz,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 13, 'Andemos como de día, honestamente: no en glotonerías y borracheras, no en lechos y disoluciones, no en pedencias y envidia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 13, 14, 'Mas vestíos del Señor Jesucristo, y no hagáis caso de la carne en sus deseos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 1, 'RECIBID al flaco en la fe, pero no para contiendas de disputas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 2, 'Porque uno cree que se ha de comer de todas cosas: otro que es débil, come legumbres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 3, 'El que come, no menosprecie al que no come: y el que no come, no juzgue al que come; porque Dios le ha levantado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 4, '¿Tú quién eres que juzgas al siervo ajeno? para su señor está en pie, ó cae: mas se afirmará; que poderoso es el Señor para afirmarle.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 5, 'Uno hace diferencia entre día y día; otro juzga iguales todos los días. Cada uno esté asegurado en su ánimo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 6, 'El que hace caso del día, háce lo para el Señor: y el que no hace caso del día, no lo hace para el Señor. El que come, come para el Señor, porque da gracias á Dios; y el que no come, no come para el Señor, y da gracias á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 7, 'Porque ninguno de nosotros vive para sí, y ninguno muere para sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 8, 'Que si vivimos, para el Señor vivimos; y si morimos, para el Señor morimos. Así que, ó que vivamos, ó que muramos, del Señor somos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 9, 'Porque Cristo para esto murió, y resucitó, y volvió á vivir, para ser Señor así de los muertos como de los que viven.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 10, 'Mas tú ¿por qué juzgas á tu hermano? ó tú también, ¿por qué menosprecias á tu hermano? porque todos hemos de estar ante el tribunal de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 11, 'Porque escrito está: Vivo yo, dice el Señor, que á mí se doblará toda rodilla, Y toda lengua confesará á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 12, 'De manera que, cada uno de nosotros dará á Dios razón de sí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 13, 'Así que, no juzguemos más los unos de los otros: antes bien juzgad de no poner tropiezo ó escándalo al hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 14, 'Yo sé, y confío en el Señor Jesús, que de suyo nada hay inmundo: mas á aquel que piensa alguna cosa ser inmunda, para él es inmunda.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 15, 'Empero si por causa de la comida tu hermano es contristado, ya no andas conforme á la caridad. No arruines con tu comida á aquél por el cual Cristo murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 16, 'No sea pues blasfemado vuestro bien:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 17, 'Que el reino de Dios no es comida ni bebida, sino justicia y paz y gozo por el Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 18, 'Porque el que en esto sirve á Cristo, agrada á Dios, y es acepto á los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 19, 'Así que, sigamos lo que hace á la paz, y á la edificación de los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 20, 'No destruyas la obra de Dios por causa de la comida. Todas las cosas á la verdad son limpias: mas malo es al hombre que come con escándalo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 21, 'Bueno es no comer carne, ni beber vino, ni nada en que tu hermano tropiece, ó se ofenda ó sea debilitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 22, '¿Tienes tú fe? Tenla para contigo delante de Dios. Bienaventurado el que no se condena á sí mismo con lo que aprueba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 14, 23, 'Mas el que hace diferencia, si comiere, es condenado, porque no comió por fe: y todo lo que no es de fe, es pecado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 1, 'ASI que, los que somos más firmes debemos sobrellevar las flaquezas de los flacos, y no agradarnos á nosotros mismos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 2, 'Cada uno de nosotros agrade á su prójimo en bien, á edificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 3, 'Porque Cristo no se agradó á sí mismo; antes bien, como está escrito: Los vituperios de los que te vituperan, cayeron sobre mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 4, 'Porque las cosas que antes fueron escritas, para nuestra enseñanza fueron escritas; para que por la paciencia, y por la consolación de las Escrituras, tengamos esperanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 5, 'Mas el Dios de la paciencia y de la consolación os dé que entre vosotros seáis unánimes según Cristo Jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 6, 'Para que concordes, á una boca glorifiquéis al Dios y Padre de nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 7, 'Por tanto, sobrellevaos los unos á los otros, como también Cristo nos sobrellevó, para gloria de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 8, 'Digo, pues, que Cristo Jesús fué hecho ministro de la circuncisión por la verdad de Dios, para confirmar las promesas hechas á los padres,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 9, 'Y para que los Gentiles glorifiquen á Dios por la misericordia; como está escrito: Por tanto yo te confesaré entre los Gentiles, Y cantaré á tu nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 10, 'Y otra vez dice: Alegraos, Gentiles, con su pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 11, 'Y otra vez: Alabad al Señor todos los Gentiles, Y magnificadle, todos los pueblos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 12, 'Y otra vez, dice Isaías: Estará la raíz de Jessé, Y el que se levantará á regir los Gentiles: Los Gentiles esperarán en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 13, 'Y el Dios de esperanza os llene de todo gozo y paz creyendo, para que abundéis en esperanza por la virtud del Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 14, 'Empero cierto estoy yo de vosotros, hermanos míos, que aun vosotros mismos estáis llenos de bodad, llenos de todo conocimiento, de tal manera que podáis amonestaros los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 15, 'Mas os he escrito, hermanos, en parte resueltamente, como amonestádoos por la gracia que de Dios me es dada,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 16, 'Para ser ministro de Jesucristo á los Gentiles, ministrando el evangelio de Dios, para que la ofrenda de los Gentiles sea agradable, santificada por el Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 17, 'Tengo, pues, de qué gloriarme en Cristo Jesús en lo que mira á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 18, 'Porque no osaría hablar alguna cosa que Cristo no haya hecho por mí para la obediencia de los Gentiles, con la palabra y con las obras,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 19, 'Con potencia de milagros y prodigios, en virtud del Espíritu de Dios: de manera que desde Jerusalem, y por los alrededores hasta Ilírico, he llenado todo del evangelio de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 20, 'Y de esta manera me esforcé á predicar el evangelio, no donde antes Cristo fuese nombrado, por no edificar sobre ajeno fundamento:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 21, 'Sino, como esta escrito: A los que no fué anunciado de él, verán: Y los que no oyeron, entenderán.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 22, 'Por lo cual aun he sido impedido muchas veces de venir á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 23, 'Mas ahora no teniendo más lugar en estas regiones, y deseando ir á vosotros muchos años há,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 24, 'Cuando partiere para España, iré á vosotros; porque espero que pasando os veré, y que seré llevado de vosotros allá, si empero antes hubiere gozado de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 25, 'Mas ahora parto para Jerusalem á ministrar á los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 26, 'Porque Macedonia y Acaya tuvieron por bien hacer una colecta para los pobres de los santos que están en Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 27, 'Porque les pareció bueno, y son deudores á ellos: porque si los Gentiles han sido hechos participantes de sus bienes espirituales, deben también ellos servirles en los carnales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 28, 'Así que, cuando hubiere concluído esto, y les hubiere consignado este fruto, pasaré por vosotros á España.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 29, 'Y sé que cuando llegue á vosotros, llegaré con abundancia de la bendición del evangelio de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 30, 'Ruégoos empero, hermanos, por el Señor nuestro Jesucristo, y por la caridad del Espíritu, que me ayudéis con oraciones por mí á Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 31, 'Que sea librado de los rebeldes que están en Judea, y que la ofrenda de mi servicio á los santos en Jerusalem sea acepta;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 32, 'Para que con gozo llegue á vosotros por la voluntad de Dios, y que sea recreado juntamente con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 15, 33, 'Y el Dios de paz sea con todos vosotros. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 1, 'ENCOMIÉNDOOS empero á Febe nuestra hermana, la cual es diaconisa de la iglesia que está en Cencreas:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 2, 'Que la recibáis en el Señor, como es digno á los santos, y que la ayudéis en cualquiera cosa en que os hubiere menester: porque ella ha ayudado á muchos, y á mí mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 3, 'Saludad á Priscila y Aquila, mis coadjutores en Cristo Jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 4, '(Que pusieron sus cuellos por mi vida: á los cuales no doy gracias yo sólo, mas aun todas las iglesias de los Gentiles;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 5, 'Asimismo á la iglesia de su casa. Saludad á Epeneto, amado mío, que es las primicias de Acaya en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 6, 'Saludad á María, la cual ha trabajado mucho con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 7, 'Saludad á Andrónico y á Junia, mis parientes, y mis compañeros en la cautividad, los que son insignes entre los apóstoles; los cuales también fueron antes de mí en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 8, 'Saludad á Amplias, amado mío en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 9, 'Saludad á Urbano, nuestro ayudador en Cristo Jesús, y á Stachîs, amado mío.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 10, 'Saludad á Apeles, probado en Cristo. Saludad á los que son de Aristóbulo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 11, 'Saludad á Herodión, mi pariente. Saludad á los que son de la casa de Narciso, los que están en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 12, 'Saludad á Trifena y á Trifosa, las cuales trabajan en el Señor. Saludad á Pérsida amada, la cual ha trabajado mucho en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 13, 'Saludad á Rufo, escogido en el Señor, y á su madre y mía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 14, 'Saludad á Asíncrito, y á Flegonte, á Hermas, á Patrobas, á Hermes, y á los hermanos que están con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 15, 'Saludad á Filólogo y á Julia, á Nereo y á su hermana, y á Olimpas, y á todos los santos que están con ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 16, 'Saludaos los unos á los otros con ósculo santo. Os saludan todas las iglesias de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 17, 'Y os ruego hermanos, que miréis los que causan disensiones y escándalos contra la doctrina que vosotros habéis aprendido; y apartaos de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 18, 'Porque los tales no sirven al Señor nuestro Jesucristo, sino á sus vientres; y con suaves palabras y bendiciones engañan los corazones de los simples.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 19, 'Porque vuestra obediencia ha venido á ser notoria á todos; así que me gozo de vosotros; mas quiero que seáis sabios en el bien, y simples en el mal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 20, 'Y el Dios de paz quebrantará presto á Satanás debajo de vuestros pies. la gracia del Señor nuestro Jesucristo sea con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 21, 'Os saludan Timoteo, mi coadjutor, y Lucio y Jasón y Sosipater, mis parientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 22, 'Yo Tercio, que escribí la epístola, os saludo en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 23, 'Salúdaos Gayo, mi huésped, y de toda la iglesia. Salúdaos Erasto, tesorero de la ciudad, y el hermano Cuarto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 24, 'La gracia del Señor nuestro Jesucristo sea con todos vosotros. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 25, 'Y al que puede confirmaros según mi evangelio y la predicación de Jesucristo, segun la revelación del misterio encubierto desde tiempos eternos,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 26, 'Mas manifestado ahora, y por las Escrituras de los profetas, según el mandamiento del Dios eterno, declarado á todas las gentes para que obedezcan á la fe;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('ROM', 'Romanos', 16, 27, 'Al sólo Dios sabio, sea gloria por Jesucristo para siempre. Amén. enviada por medio de Febe, diaconisa de la iglesia de Cencreas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 1, 'PABLO, llamado á ser apóstol de Jesucristo por la voluntad de Dios, y Sóstenes el hermano,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 2, 'A la iglesia de Dios que está en Corinto, santificados en Cristo Jesús, llamados santos, y á todos los que invocan el nombre de nuestro Señor Jesucristo en cualquier lugar, Señor de ellos y nuestro:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 3, 'Gracia y paz de Dios nuestro Padre, y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 4, 'Gracias doy á mi Dios siempre por vosotros, por la gracia de Dios que os es dada en Cristo Jesús;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 5, 'Que en todas las cosas sois enriquecidos en él, en toda lengua y en toda ciencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 6, 'Así como el testimonio de Cristo ha sido confirmado en vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 7, 'De tal manera que nada os falte en ningún don, esperando la manifestación de nuestro Señor Jesucristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 8, 'El cual también os confirmará hasta el fin, para que seáis sin falta en el día de nuestro Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 9, 'Fiel es Dios, por el cual sois llamados á la participación de su Hijo Jesucristo nuestro Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 10, 'Os ruego pues, hermanos, por el nombre de nuestro Señor Jesucristo, que habléis todos una misma cosa, y que no haya entre vosotros disensiones, antes seáis perfectamente unidos en una misma mente y en un mismo parecer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 11, 'Porque me ha sido declarado de vosotros, hermanos míos, por los que son de Cloé, que hay entre vosotros contiendas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 12, 'Quiero decir, que cada uno de vosotros dice: Yo cierto soy de Pablo; pues yo de Apolos; y yo de Cefas; y yo de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 13, '¿Está dividido Cristo? ¿Fué crucificado Pablo por vosotros? ¿ó habéis sido bautizados en el nombre de Pablo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 14, 'Doy gracias á Dios, que á ninguno de vosotros he bautizado, sino á Crispo y á Gayo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 15, 'Para que ninguno diga que habéis sido bautizados en mi nombre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 16, 'Y también bauticé la familia de Estéfanas: mas no sé si he bautizado algún otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 17, 'Porque no me envió Cristo á bautizar, sino á predicar el evangelio: no en sabiduría de palabras, porque no sea hecha vana la cruz de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 18, 'Porque la palabra de la cruz es locura á los que se pierden; mas á los que se salvan, es á saber, á nosotros, es potencia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 19, 'Porque está escrito: Destruiré la sabiduría de los sabios, Y desecharé la inteligencia de los entendidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 20, '¿Qué es del sabio? ¿qué del escriba? ¿qué del escudriñador de este siglo? ¿no ha enloquecido Dios la sabiduría del mundo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 21, 'Porque por no haber el mundo conocido en la sabiduría de Dios á Dios por sabiduría, agradó á Dios salvar á los creyentes por la locura de la predicación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 22, 'Porque los Judíos piden señales, y los Griegos buscan sabiduría:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 23, 'Mas nosotros predicamos á Cristo crucificado, á los Judíos ciertamente tropezadero, y á los Gentiles locura;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 24, 'Empero á los llamados, así Judíos como Griegos, Cristo potencia de Dios, y sabiduría de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 25, 'Porque lo loco de Dios es más sabio que los hombres; y lo flaco de Dios es más fuerte que los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 26, 'Porque mirad, hermanos, vuestra vocación, que no sois muchos sabios según la carne, no muchos poderosos, no muchos nobles;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 27, 'Antes lo necio del mundo escogió Dios, para avergonzar á los sabios; y lo flaco del mundo escogió Dios, para avergonzar lo fuerte;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 28, 'Y lo vil del mundo y lo menos preciado escogió Dios, y lo que no es, para deshacer lo que es:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 29, 'Para que ninguna carne se jacte en su presencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 30, 'Mas de él sois vosotros en Cristo Jesús, el cual nos ha sido hecho por Dios sabiduría, y justificación, y santificación, y redención:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 1, 31, 'Para que, como está escrito: El que se gloría, gloríese en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 1, 'ASI que, hermanos, cuando fuí á vosotros, no fuí con altivez de palabra, ó de sabiduría, á anunciaros el testimonio de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 2, 'Porque no me propuse saber algo entre vosotros, sino á Jesucristo, y á éste crucificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 3, 'Y estuve yo con vosotros con flaqueza, y mucho temor y temblor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 4, 'Y ni mi palabra ni mi predicación fué con palabras persuasivas de humana sabiduría, mas con demostración del Espíritu y de poder;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 5, 'Para que vuestra fe no esté fundada en sabiduría de hombres, mas en poder de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 6, 'Empero hablamos sabiduría de Dios entre perfectos; y sabiduría, no de este siglo, ni de los príncipes de este siglo, que se deshacen:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 7, 'Mas hablamos sabiduría de Dios en misterio, la sabiduría oculta, la cual Dios predestinó antes de los siglos para nuestra gloria:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 8, 'La que ninguno de los príncipes de este siglo conoció; porque si la hubieran conocido, nunca hubieran crucificado al Señor de gloria:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 9, 'Antes, como está escrito: Cosas que ojo no vió, ni oreja oyó, Ni han subido en corazón de hombre, Son las que ha Dios preparado para aquellos que le aman.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 10, 'Empero Dios nos lo reveló á nosotros por el Espíritu: porque el Espíritu todo lo escudriña, aun lo profundo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 11, 'Porque ¿quién de los hombres sabe las cosas del hombre, sino el espíritu del hombre que está en él? Así tampoco nadie conoció las cosas de Dios, sino el Espíritu de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 12, 'Y nosotros hemos recibido, no el espíritu del mundo, sino el Espíritu que es de Dios, para que conozcamos lo que Dios nos ha dado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 13, 'Lo cual también hablamos, no con doctas palabras de humana sabiduría, mas con doctrina del Espíritu, acomodando lo espiritual á lo espiritual.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 14, 'Mas el hombre animal no percibe las cosas que son del Espíritu de Dios, porque le son locura: y no las puede entender, porque se han de examinar espiritualmente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 15, 'Empero el espiritual juzga todas las cosas; mas él no es juzgado de nadie.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 2, 16, 'Porque ¿quién conoció la mente del Señor? ¿quién le instruyó? Mas nosotros tenemos la mente de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 1, 'DE manera que yo, hermanos, no pude hablaros como á espirituales, sino como á carnales, como á niños en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 2, 'Os dí á beber leche, y no vianda: porque aun no podíais, ni aun podéis ahora;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 3, 'Porque todavía sois carnales: pues habiendo entre vosotros celos, y contiendas, y disensiones, ¿no sois carnales, y andáis como hombres?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 4, 'Porque diciendo el uno: Yo cierto soy de Pablo; y el otro: Yo de Apolos; ¿no sois carnales?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 5, '¿Qué pues es Pablo? ¿y qué es Apolos? Ministros por los cuales habéis creído; y eso según que á cada uno ha concedido el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 6, 'Yo planté, Apolos regó: mas Dios ha dado el crecimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 7, 'Así que, ni el que planta es algo, ni el que riega; sino Dios, que da el crecimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 8, 'Y el que planta y el que riega son una misma cosa; aunque cada uno recibirá su recompensa conforme á su labor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 9, 'Porque nosotros, coadjutores somos de Dios; y vosotros labranza de Dios sois, edificio de Dios sois.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 10, 'Conforme á la gracia de Dios que me ha sido dada, yo como perito arquitecto puse el fundamento, y otro edifica encima: empero cada uno vea cómo sobreedifica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 11, 'Porque nadie puede poner otro fundamento que el que está puesto, el cual es Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 12, 'Y si alguno edificare sobre este fundamento oro, plata, piedras preciosas, madera, heno, hojarasca;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 13, 'La obra de cada uno será manifestada: porque el día la declarará; porque por el fuego será manifestada; y la obra de cada uno cuál sea, el fuego hará la prueba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 14, 'Si permaneciere la obra de alguno que sobreedificó, recibirá recompensa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 15, 'Si la obra de alguno fuere quemada, será perdida: él empero será salvo, mas así como por fuego.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 16, '¿No sabéis que sois templo de Dios, y que el Espíritu de Dios mora en vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 17, 'Si alguno violare el templo de Dios, Dios destruirá al tal: porque el templo de Dios, el cual sois vosotros, santo es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 18, 'Nadie se engañe á sí mismo: si alguno entre vosotros parece ser sabio en este siglo, hágase simple, para ser sabio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 19, 'Porque la sabiduría de esta mundo es necedad para con Dios; pues escrito está: El que prende á los sabios en la astucia de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 20, 'Y otra vez: El Señor conoce los pensamientos de los sabios, que son vanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 21, 'Así que, ninguno se gloríe en los hombres; porque todo es vuestro,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 22, 'Sea Pablo, sea Apolos, sea Cefas, sea el mundo, sea la vida, sea la muerte, sea lo presente, sea los por venir; todo es vuestro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 3, 23, 'Y vosotros de Cristo; y Cristo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 1, 'TÉNGANNOS los hombres por ministros de Cristo, y dispensadores de los misterios de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 2, 'Mas ahora se requiere en los dispensadores, que cada uno sea hallado fiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 3, 'Yo en muy poco tengo el ser juzgado de vosotros, ó de juicio humano; y ni aun yo me juzgo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 4, 'Porque aunque de nada tengo mala conciencia, no por eso soy justificado; mas el que me juzga, el Señor es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 5, 'Así que, no juzguéis nada antes de tiempo, hasta que venga el Señor, el cual también aclarará lo oculto de las tinieblas, y manifestará los intentos de los corazones: y entonces cada uno tendrá de Dios la alabanza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 6, 'Esto empero, hermanos, he pasado por ejemplo en mí y en Apolos por amor de vosotros; para que en nosotros aprendáis á no saber más de lo que está escrito, hinchándoos por causa de otro el uno contra el otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 7, 'Porque ¿quién te distingue? ¿ó qué tienes que no hayas recibido? Y si lo recibiste, ¿de qué te glorías como si no hubieras recibido?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 8, 'Ya estáis hartos, ya estáis ricos, sin nosotros reináis; y ojalá reinéis, para que nosotros reinemos también juntamente con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 9, 'Porque á lo que pienso, Dios nos ha mostrado á nosotros los apóstoles por los postreros, como á sentenciados á muerte: porque somos hechos espectáculo al mundo, y á los ángeles, y á los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 10, 'Nosotros necios por amor de Cristo, y vosotros prudentes en Cristo; nosotros flacos, y vosotros fuertes; vosotros nobles, y nosotros viles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 11, 'Hasta esta hora hambreamos, y tenemos sed, y estamos desnudos, y somos heridos de golpes, y andamos vagabundos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 12, 'Y trabajamos, obrando con nuestras manos: nos maldicen, y bendecimos: padecemos persecución, y sufrimos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 13, 'Somos blasfemados, y rogamos: hemos venido á ser como la hez del mundo, el desecho de todos hasta ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 14, 'No escribo esto para avergonzaros: mas amonéstoos como á mis hijos amados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 15, 'Porque aunque tengáis diez mil ayos en Cristo, no tendréis muchos padres; que en Cristo Jesús yo os engendré por el evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 16, 'Por tanto, os ruego que me imitéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 17, 'Por lo cual os he enviado á Timoteo, que es mi hijo amado y fiel en el Señor, el cual os amonestará de mis caminos cuáles sean en Cristo, de la manera que enseño en todas partes en todas las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 18, 'Mas algunos están envanecidos, como si nunca hubiese yo de ir á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 19, 'Empero iré presto á vosotros, si el Señor quisiere; y entenderé, no las palabras de los que andan hinchados, sino la virtud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 20, 'Porque el reino de Dios no consiste en palabras, sino en virtud.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 4, 21, '¿Qué queréis? ¿iré á vosotros con vara, ó con caridad y espíritu de mansedumbre?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 1, 'DE cierto se oye que hay entre vosotros fornicación, y tal fornicación cual ni aun se nombra entre los Gentiles; tanto que alguno tenga la mujer de su padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 2, 'Y vosotros estáis hinchados, y no más bien tuvisteis duelo, para que fuese quitado de en medio de vosotros el que hizo tal obra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 3, 'Y ciertamente, como ausente con el cuerpo, mas presente en espíritu, ya como presente he juzgado al que esto así ha cometido:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 4, 'En el nombre del Señor nuestro Jesucristo, juntados vosotros y mi espíritu, con la facultad de nuestro Señor Jesucristo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 5, 'El tal sea entregado á Satanás para muerte de la carne, porque el espíritu sea salvo en el día del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 6, 'No es buena vuestra jactancia. ¿No sabéis que un poco de levadura leuda toda la masa?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 7, 'Limpiad pues la vieja levadura, para que seáis nueva masa, como sois sin levadura: porque nuestra pascua, que es Cristo, fué sacrificada por nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 8, 'Así que hagamos fiesta, no en la vieja levadura, ni en la levadura de malicia y de maldad, sino en ázimos de sinceridad y de verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 9, 'Os he escrito por carta, que no os envolváis con los fornicarios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 10, 'No absolutamente con los fornicarios de este mundo, ó con los avaros, ó con los ladrones, ó con los idólatras; pues en tal caso os sería menester salir del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 11, 'Mas ahora os he escrito, que no os envolváis, es á saber, que si alguno llamándose hermano fuere fornicario, ó avaro, ó idólatra, ó maldiciente, ó borracho, ó ladrón, con el tal ni aun comáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 12, 'Porque ¿qué me va á mí en juzgar á los que están fuera? ¿No juzgáis vosotros á los que están dentro?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 5, 13, 'Porque á los que están fuera, Dios juzgará: quitad pues á ese malo de entre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 1, '¿OSA alguno de vosotros, teniendo algo con otro, ir á juicio delante de los injustos, y no delante de los santos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 2, '¿O no sabéis que los santos han de juzgar al mundo? Y si el mundo ha de ser juzgado por vosotros, ¿sois indignos de juzgar cosas muy pequeñas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 3, '¿O no sabéis que hemos de juzgar á los angeles? ¿cuánto más las cosas de este siglo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 4, 'Por tanto, si hubiereis de tener juicios de cosas de este siglo, poned para juzgar á los que son de menor estima en la iglesia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 5, 'Para avergonzaros lo digo. ¿Pues qué, no hay entre vosotros sabio, ni aun uno que pueda juzgar entre sus hermanos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 6, 'Sino que el hermano con el hermano pleitea en juicio, y esto ante los infieles?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 7, 'Así que, por cierto es ya una falta en vosotros que tengáis pleitos entre vosotros mismos. ¿Por qué no sufrís antes la injuria? ¿por qué no sufrís antes ser defraudados?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 8, 'Empero vosotros hacéis la injuria, y defraudáis, y esto á los hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 9, '¿No sabéis que los injustos no poseerán el reino de Dios? No erréis, que ni los fornicarios, ni los idólatras, ni los adúlteros, ni los afeminados, ni los que se echan con varones,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 10, 'Ni los ladrones, ni los avaros, ni los borrachos, ni los maldicientes, ni los robadores, heredarán el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 11, 'Y esto erais algunos: mas ya sois lavados, mas ya sois santificados, mas ya sois justificados en el nombre del Señor Jesús, y por el Espíritu de nuestro Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 12, 'Todas las cosas me son lícitas, mas no todas convienen: todas las cosas me son lícitas, mas yo no me meteré debajo de potestad de nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 13, 'Las viandas para el vientre, y el vientre para las viandas; empero y á él y á ellas deshará Dios. Mas el cuerpo no es para la fornicación, sino para el Señor; y el Señor para el cuerpo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 14, 'Y Dios que levantó al Señor, también á nosotros nos levantará con su poder.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 15, '¿No sabéis que vuestros cuerpos son miembros de Cristo? ¿Quitaré pues los miembros de Cristo, y los haré miembros de una ramera? Lejos sea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 16, '¿O no sabéis que el que se junta con una ramera, es hecho con ella un cuerpo? porque serán, dice, los dos en una carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 17, 'Empero el que se junta con el Señor, un espíritu es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 18, 'Huid la fornicación. Cualquier otro pecado que el hombre hiciere, fuera del cuerpo es; mas el que fornica, contra su propio cuerpo peca.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 19, '¿O ignoráis que vuestro cuerpo es templo del Espíritu Santo, el cual está en vosotros, el cual tenéis de Dios, y que no sois vuestros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 6, 20, 'Porque comprados sois por precio: glorificad pues á Dios en vuestro cuerpo y en vuestro espíritu, los cuales son de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 1, 'CUANTO á las cosas de que me escribisteis, bien es al hombre no tocar mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 2, 'Mas á causa de las fornicaciones, cada uno tenga su mujer, y cada una tenga su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 3, 'El marido pague á la mujer la debida benevolencia; y asimismo la mujer al marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 4, 'La mujer no tiene potestad de su propio cuerpo, sino el marido: é igualmente tampoco el marido tiene potestad de su propio cuerpo, sino la mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 5, 'No os defraudéis el uno al otro, á no ser por algún tiempo de mutuo consentimiento, para ocuparos en la oración: y volved á juntaros en uno, porque no os tiente Satanás á causa de vuestra incontinencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 6, 'Mas esto digo por permisión, no por mandamiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 7, 'Quisiera más bien que todos los hombres fuesen como yo: empero cada uno tiene su propio don de Dios; uno á la verdad así, y otro así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 8, 'Digo pues á los solteros y á las viudas, que bueno les es si se quedaren como yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 9, 'Y si no tienen don de continencia, cásense; que mejor es casarse que quemarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 10, 'Mas á los que están juntos en matrimonio, denuncio, no yo, sino el Señor: Que la mujer no se aparte del marido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 11, 'Y si se apartare, que se quede sin casar, ó reconcíliese con su marido; y que el marido no despida á su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 12, 'Y á los demás yo digo, no el Señor: si algún hermano tiene mujer infiel, y ella consiente en habitar con él, no la despida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 13, 'Y la mujer que tiene marido infiel, y él consiente en habitar con ella, no lo deje.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 14, 'Porque el marido infiel es santificado en la mujer, y la mujer infiel en el marido: pues de otra manera vuestros hijos serían inmundos; empero ahora son santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 15, 'Pero si el infiel se aparta, apártese: que no es el hermano ó la hermana sujeto á servidumbre en semejante caso; antes á paz nos llamó Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 16, 'Porque ¿de dónde sabes, oh mujer, si quizá harás salva á tu marido? ¿ó de dónde sabes, oh marido, si quizá harás salvo á tu mujer?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 17, 'Empero cada uno como el Señor le repartió, y como Dios llamó á cada uno, así ande: y así enseño en todas las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 18, '¿Es llamado alguno circuncidado? quédese circunciso. ¿Es llamado alguno incircuncidado? que no se circuncide.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 19, 'La circuncisión nada es, y la incircuncisión nada es; sino la observancia de las mandamientos de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 20, 'Cada uno en la vocación en que fué llamado, en ella se quede.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 21, '¿Eres llamado siendo siervo? no se te dé cuidado; mas también si puedes hacerte libre, procúralo más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 22, 'Porque el que en el Señor es llamado siendo siervo, liberto es del Señor: asimismo también el que es llamado siendo libre, siervo es de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 23, 'Por precio sois comprados; no os hagáis siervos de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 24, 'Cada uno, hermanos, en lo que es llamado, en esto se quede para con Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 25, 'Empero de las vírgenes no tengo mandamiento del Señor; mas doy mi parecer, como quien ha alcanzado misericordia del Señor para ser fiel.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 26, 'Tengo, pues, esto por bueno á causa de la necesidad que apremia, que bueno es al hombre estarse así.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 27, '¿Estás ligado á mujer? no procures soltarte. ¿Estáis suelto de mujer? no procures mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 28, 'Mas también si tomares mujer, no pecaste; y si la doncella se casare, no pecó: pero aflicción de carne tendrán los tales; mas yo os dejo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 29, 'Esto empero digo, hermanos, que el tiempo es corto: lo que resta es, que los que tienen mujeres sean como los que no las tienen,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 30, 'Y los que lloran, como los que no lloran; y los que se huelgan, como los que no se huelgan; y los que compran, como los que no poseen;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 31, 'Y los que usan de este mundo, como los que no usan: porque la apariencia de este mundo se pasa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 32, 'Quisiera, pues, que estuvieseis sin congoja. El soltero tiene cuidado de las cosas que son del Señor, cómo ha de agradar al Señor:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 33, 'Empero el que se casó tiene cuidado de las cosas que son del mundo, cómo ha de agradar á su mujer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 34, 'Hay asimismo diferencia entre la casada y la doncella: la doncella tiene cuidado de las cosas del Señor, para ser santa así en el cuerpo como en el espíritu: mas la casada tiene cuidado de las cosas del mundo, cómo ha de agradar á su marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 35, 'Esto empero digo para vuestro provecho; no para echaros lazo, sino para lo honesto y decente, y para que sin impedimento os lleguéis al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 36, 'Mas, si á alguno parece cosa fea en su hija virgen, que pase ya de edad, y que así conviene que se haga, haga lo que quisiere, no peca; cásese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 37, 'Pero el que está firme en su corazón, y no tiene necesidad, sino que tiene libertad de su voluntad, y determinó en su corazón esto, el guardar su hija virgen, bien hace.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 38, 'Así que, el que la da en casamiento, bien hace; y el que no la da en casamiento, hace mejor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 39, 'La mujer casada está atada á la ley, mientras vive su marido; mas si su marido muriere, libre es: cásese con quien quisiere, con tal que sea en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 7, 40, 'Empero más venturosa será si se quedare así, según mi consejo; y pienso que también yo tengo Espíritu de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 1, 'Y POR lo que hace á lo sacrificado á los ídolos, sabemos que todos tenemos ciencia. La ciencia hincha, mas la caridad edifica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 2, 'Y si alguno se imagina que sabe algo, aun no sabe nada como debe saber.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 3, 'Mas si alguno ama á Dios, el tal es conocido de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 4, 'Acerca, pues, de las viandas que son saacrificadas á los ídolos, sabemos que el ídolo nada es en el mundo, y que no hay más de un Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 5, 'Porque aunque haya algunos que se llamen dioses, ó en el cielo, ó en la tierra (como hay muchos dioses y muchos señores),');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 6, 'Nosotros empero no tenemos más de un Dios, el Padre, del cual son todas las cosas, y nosotros en él: y un Señor Jesucristo, por el cual son todas las cosas, y nosotros por él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 7, 'Mas no en todos hay esta ciencia: porque algunos con conciencia del ídolo hasta aquí, comen como sacrificado á ídolos; y su conciencia, siendo flaca, es contaminada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 8, 'Si bien la vianda no nos hace más aceptos á Dios: porque ni que comamos, seremos más ricos; ni que no comamos, seremos más pobres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 9, 'Mas mirad que esta vuestra libertad no sea tropezadero á los que son flacos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 10, 'Porque si te ve alguno, á ti que tienes ciencia, que estás sentado á la mesa en el lugar de los ídolos, ¿la conciencia de aquel que es flaco, no será adelantada á comer de lo sacrificado á los ídolos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 11, 'Y por tu ciencia se perderá el hermano flaco por el cual Cristo murió.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 12, 'De esta manera, pues, pecando contra los hermanos, é hiriendo su flaca conciencia, contra Cristo pecáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 8, 13, 'Por lo cual, si la comida es á mi hermano ocasión de caer, jamás comeré carne por no escandalizar á mi hermano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 1, '¿NO soy apóstol? ¿no soy libre? ¿no he visto á Jesús el Señor nuestro? ¿no sois vosotros mi obra en el Señor?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 2, 'Si á los otros no soy apóstol, á vosotros ciertamente lo soy: porque el sello de mi apostolado sois vosotros en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 3, 'Esta es mi respuesta á los que me preguntan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 4, 'Qué, ¿no tenemos potestad de comer y de beber?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 5, '¿No tenemos potestad de traer con nosotros una hermana mujer también como los otros apóstoles, y los hermanos del Señor, y Cefas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 6, '¿O sólo yo y Bernabé no tenemos potestad de no trabajar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 7, '¿Quién jamás peleó á sus expensas? ¿quién planta viña, y no come de su fruto? ¿ó quién apacienta el ganado, y no come de la leche del ganado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 8, '¿Digo esto según los hombres? ¿no dice esto también la ley?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 9, 'Porque en la ley de Moisés está escrito: No pondrás bozal al buey que trilla. ¿Tiene Dios cuidado de los bueyes?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 10, '¿O dícelo enteramente por nosotros? Pues por nosotros está escrito: porque con esperanza ha de arar el que ara; y el que trilla, con esperanza de recibir el fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 11, 'Si nosotros os sembramos lo espiritual, ¿es gran cosa si segáremos lo vuestro carnal?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 12, 'Si otros tienen en vosotros esta potestad, ¿no más bien nosotros? Mas no hemos usado de esta potestad: antes lo sufrimos todo, por no poner ningún obstáculo al evangelio de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 13, '¿No sabéis que los que trabajan en el santuario, comen del santuario; y que los que sirven al altar, del altar participan?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 14, 'Así también ordenó el Señor á los que anuncian el evangelio, que vivan del evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 15, 'Mas yo de nada de esto me aproveché: ni tampoco he escrito esto para que se haga así conmigo; porque tengo por mejor morir, antes que nadie haga vana esta mi gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 16, 'Pues bien que anuncio el evangelio, no tengo por qué gloriarme porque me es impuesta necesidad; y ¡ay de mí si no anunciare el evangelio!');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 17, 'Por lo cual, si lo hago de voluntad, premio tendré; mas si por fuerza, la dispensación me ha sido encargada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 18, '¿Cuál, pues, es mi merced? Que predicando el evangelio, ponga el evangelio de Cristo de balde, para no usar mal de mi potestad en el evangelio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 19, 'Por lo cual, siendo libre para con todos, me he hecho siervo de todos por ganar á más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 20, 'Heme hecho á los Judíos como Judío, por ganar á los Judíos; á los que están sujetos á la ley (aunque yo no sea sujeto á la ley) como sujeto á la ley, por ganar á los que están sujetos á la ley;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 21, 'A los que son sin ley, como si yo fuera sin ley, (no estando yo sin ley de Dios, mas en la ley de Cristo) por ganar á los que estaban sin ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 22, 'Me he hecho á los flacos flaco, por ganar á los flacos: á todos me he hecho todo, para que de todo punto salve á algunos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 23, 'Y esto hago por causa del evangelio, por hacerme juntamente participante de él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 24, '¿No sabéis que los que corren en el estadio, todos á la verdad corren, mas uno lleva el premio? Corred de tal manera que lo obtengáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 25, 'Y todo aquel que lucha, de todo se abstiene: y ellos, á la verdad, para recibir una corona corruptible; mas nosotros, incorruptible.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 26, 'Así que, yo de esta manera corro, no como á cosa incierta; de esta manera peleo, no como quien hiere el aire:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 9, 27, 'Antes hiero mi cuerpo, y lo pongo en servidumbre; no sea que, habiendo predicado á otros, yo mismo venga á ser reprobado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 1, 'PORQUE no quiero, hermanos, que ignoréis que nuestros padres todos estuvieron bajo la nube, y todos pasaron la mar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 2, 'Y todos en Moisés fueron bautizados en la nube y en la mar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 3, 'Y todos comieron la misma vianda espiritual;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 4, 'Y todos bebieron la misma bebida espiritual; porque bebían de la piedra espiritual que los seguía, y la piedra era Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 5, 'Mas de muchos de ellos no se agradó Dios; por lo cual fueron postrados en el desierto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 6, 'Empero estas cosas fueron en figura de nosotros, para que no codiciemos cosas malas, como ellos codiciaron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 7, 'Ni seáis honradores de ídolos, como algunos de ellos, según está escrito: Sentóse el pueblo á comer y á beber, y se levantaron á jugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 8, 'Ni forniquemos, como algunos de ellos fornicaron, y cayeron en un día veinte y tres mil.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 9, 'Ni tentemos á Cristo, como también algunos de ellos le tentaron, y perecieron por las serpientes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 10, 'Ni murmuréis, como algunos de ellos murmuraron, y perecieron por el destructor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 11, 'Y estas cosas les acontecieron en figura; y son escritas para nuestra admonición, en quienes los fines de los siglos han parado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 12, 'Así que, el que piensa estar firme, mire no caiga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 13, 'No os ha tomado tentación, sino humana: mas fiel es Dios, que no os dejará ser tentados más de lo que podeís llevar; antes dará también juntamente con la tentación la salida, para que podáis aguantar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 14, 'Por tanto, amados míos, huid de la idolatría.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 15, 'Como á sabios hablo; juzgad vosotros lo que digo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 16, 'La copa de bendición que bendecimos, ¿no es la comunión de la sangre de Cristo? El pan que partimos, ¿no es la comunión del cuerpo de Cristo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 17, 'Porque un pan, es que muchos somos un cuerpo; pues todos participamos de aquel un pan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 18, 'Mirad á Israel según la carne: los que comen de los sacrificios ¿no son partícipes con el altar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 19, '¿Qué pues digo? ¿Que el ídolo es algo? ¿ó que sea algo lo que es sacrificado á los ídolos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 20, 'Antes digo que lo que los Gentiles sacrifican, á los demonios lo sacrifican, y no á Dios: y no querría que vosotros fueseis partícipes con los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 21, 'No podéis beber la copa del Señor, y la copa de los demonios: no podéis ser partícipes de la mesa del Señor, y de la mesa de los demonios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 22, '¿O provocaremos á celo al Señor? ¿Somos más fuertes que él?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 23, 'Todo me es lícito, mas no todo conviene: todo me es lícito, mas no todo edifica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 24, 'Ninguno busque su propio bien, sino el del otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 25, 'De todo lo que se vende en la carnicería, comed, sin preguntar nada por causa de la conciencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 26, 'Porque del Señor es la tierra y lo que la hinche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 27, 'Y si algún infiel os llama, y queréis ir, de todo lo que se os pone delante comed, sin preguntar nada por causa de la conciencia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 28, 'Mas si alguien os dijere: Esto fué sacrificado á los ídolos: no lo comáis, por causa de aquel que lo declaró, y por causa de la conciencia: porque del Señor es la tierra y lo que la hinche.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 29, 'La conciencia, digo, no tuya, sino del otro. Pues ¿por qué ha de ser juzgada mi libertad por otra conciencia?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 30, 'Y si yo con agradecimiento participo, ¿por qué he de ser blasfemado por lo que doy gracias?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 31, 'Si pues coméis, ó bebéis, ó hacéis otra cosa, haced lo todo á gloria de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 32, 'Sed sin ofensa á Judíos, y á Gentiles, y á la iglesia de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 10, 33, 'Como también yo en todas las cosas complazco á todos, no procurando mi propio beneficio, sino el de muchos, para que sean salvos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 1, 'SED imitadores de mí, así como yo de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 2, 'Y os alabo, hermanos, que en todo os acordáis de mi, y retenéis las instrucciones mías, de la manera que os enseñé.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 3, 'Mas quiero que sepáis, que Cristo es la cabeza de todo varón; y el varón es la cabeza de la mujer; y Dios la cabeza de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 4, 'Todo varón que ora ó profetiza cubierta la cabeza, afrenta su cabeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 5, 'Mas toda mujer que ora ó profetiza no cubierta su cabeza, afrenta su cabeza; porque lo mismo es que si se rayese.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 6, 'Porque si la mujer no se cubre, trasquílese también: y si es deshonesto á la mujer trasquilarse ó raerse, cúbrase.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 7, 'Porque el varón no ha de cubrir la cabeza, porque es imagen y gloria de Dios: mas la mujer es gloria del varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 8, 'Porque el varón no es de la mujer, sino la mujer del varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 9, 'Porque tampoco el varón fué criado por causa de la mujer, sino la mujer por causa del varón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 10, 'Por lo cual, la mujer debe tener señal de potestad sobre su cabeza, por causa de los ángeles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 11, 'Mas ni el varón sin la mujer, ni la mujer sin el varón, en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 12, 'Porque como la mujer es del varón, así también el varón es por la mujer: empero todo de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 13, 'Juzgad vosotros mismos: ¿es honesto orar la mujer á Dios no cubierta?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 14, 'La misma naturaleza ¿no os enseña que al hombre sea deshonesto criar cabello?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 15, 'Por el contrario, á la mujer criar el cabello le es honroso; porque en lugar de velo le es dado el cabello.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 16, 'Con todo eso, si alguno parece ser contencioso, nosotros no tenemos tal costumbre, ni las iglesias de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 17, 'Esto empero os denuncio, que no alabo, que no por mejor sino por peor os juntáis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 18, 'Porque lo primero, cuando os juntáis en la iglesia, oigo que hay entre vosotros disensiones; y en parte lo creo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 19, 'Porque preciso es que haya entre vosotros aun herejías, para que los que son probados se manifiesten entre vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 20, 'Cuando pues os juntáis en uno, esto no es comer la cena del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 21, 'Porque cada uno toma antes para comer su propia cena; y el uno tiene hambre, y el otro está embriagado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 22, 'Pues qué, ¿no tenéis casas en que comáis y bebáis? ¿ó menospreciáis la iglesia de Dios, y avergonzáis á los que no tienen? ¿Qué os diré? ¿os alabaré? En esto no os alabo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 23, 'Porque yo recibí del Señor lo que también os he enseñado: Que el Señor Jesús, la noche que fué entregado, tomó pan;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 24, 'Y habiendo dado gracias, lo partió, y dijo: Tomad, comed: esto es mi cuerpo que por vosotros es partido: haced esto en memoria de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 25, 'Asimismo tomó también la copa, después de haber cenado, diciendo: Esta copa es el nuevo pacto en mi sangre: haced esto todas las veces que bebiereis, en memoria de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 26, 'Porque todas las veces que comiereis este pan, y bebiereis esta copa, la muerte del Señor anunciáis hasta que venga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 27, 'De manera que, cualquiera que comiere este pan ó bebiere esta copa del Señor indignamente, será culpado del cuerpo y de la sangre del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 28, 'Por tanto, pruébese cada uno á sí mismo, y coma así de aquel pan, y beba de aquella copa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 29, 'Porque el que come y bebe indignamente, juicio come y bebe para sí, no discerniendo el cuerpo del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 30, 'Por lo cual hay muchos enfermos y debilitados entre vosotros; y muchos duermen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 31, 'Que si nos examinásemos á nosotros mismos, cierto no seríamos juzgados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 32, 'Mas siendo juzgados, somos castigados del Señor, para que no seamos condenados con el mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 33, 'Así, que, hermanos míos, cuando os juntáis á comer, esperaos unos á otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 11, 34, 'Si alguno tuviere hambre, coma en su casa, porque no os juntéis para juicio. Las demás cosas ordenaré cuando llegare.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 1, 'Y ACERCA de los dones espirituales, no quiero, hermanos, que ignoréis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 2, 'Sabéis que cuando erais Gentiles, ibais, como erais llevados, a los ídolos mudos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 3, 'Por tanto os hago saber, que nadie que hable por Espíritu de Dios, llama anatema á Jesús; y nadie puede llamar á Jesús Señor, sino por Espíritu Santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 4, 'Empero hay repartimiento de dones; mas el mismo Espíritu es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 5, 'Y hay repartimiento de ministerios; mas el mismo Señor es.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 6, 'Y hay repartimiento de operaciones; mas el mismo Dios es el que obra todas las cosas en todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 7, 'Empero á cada uno le es dada manifestación del Espíritu para provecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 8, 'Porque á la verdad, á éste es dada por el Espíritu palabra de sabiduría; á otro, palabra de ciencia según el mismo Espíritu;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 9, 'A otro, fe por el mismo Espíritu, y á otro, dones de sanidades por el mismo Espíritu;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 10, 'A otro, operaciones de milagros, y á otro, profecía; y á otro, discreción de espíritus; y á otro, géneros de lenguas; y á otro, interpretación de lenguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 11, 'Mas todas estas cosas obra uno y el mismo Espíritu, repartiendo particularmente á cada uno como quiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 12, 'Porque de la manera que el cuerpo es uno, y tiene muchos miembros, empero todos los miembros del cuerpo, siendo muchos, son un cuerpo, así también Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 13, 'Porque por un Espíritu somos todos bautizados en un cuerpo, ora Judíos ó Griegos, ora siervos ó libres; y todos hemos bebido de un mismo Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 14, 'Pues ni tampoco el cuerpo es un miembro, sino muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 15, 'Si dijere el pie: Porque no soy mano, no soy del cuerpo: ¿por eso no será del cuerpo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 16, 'Y si dijere la oreja: Porque no soy ojo, no soy del cuerpo: ¿por eso no será del cuerpo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 17, 'Si todo el cuerpo fuese ojo, ¿dónde estaría el oído? Si todo fuese oído, ¿dónde estaría el olfato?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 18, 'Mas ahora Dios ha colocado los miembros cada uno de ellos en el cuerpo, como quiso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 19, 'Que si todos fueran un miembro, ¿dónde estuviera el cuerpo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 20, 'Mas ahora muchos miembros son á la verdad, empero un cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 21, 'Ni el ojo puede decir á la mano: No te he menester: ni asimismo la cabeza á los pies: No tengo necesidad de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 22, 'Antes, mucho más los miembros del cuerpo que parecen más flacos, son necesarios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 23, 'Y á aquellos del cuerpo que estimamos ser más viles, á éstos vestimos más honrosamente; y los que en nosotros son menos honestos, tienen más compostura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 24, 'Porque los que en nosotros son más honestos, no tienen necesidad: mas Dios ordenó el cuerpo, dando más abundante honor al que le faltaba;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 25, 'Para que no haya desavenencia en el cuerpo, sino que los miembros todos se interesen los unos por los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 26, 'Por manera que si un miembro padece, todos los miembros á una se duelen; y si un miembro es honrado, todos los miembros á una se gozan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 27, 'Pues vosotros sois el cuerpo de Cristo, y miembros en parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 28, 'Y á unos puso Dios en la iglesia, primeramente apóstoles, luego profetas, lo tercero doctores; luego facultades; luego dones de sanidades, ayudas, gobernaciones, géneros de lenguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 29, '¿Son todos apóstoles? ¿son todos profetas? ¿todos doctores? ¿todos facultades?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 30, '¿Tienen todos dones de sanidad? ¿hablan todos lenguas? ¿interpretan todos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 12, 31, 'Empero procurad los mejores dones; mas aun yo os muestro un camino más excelente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 1, 'SI yo hablase lenguas humanas y angélicas, y no tengo caridad, vengo á ser como metal que resuena, ó címbalo que retiñe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 2, 'Y si tuviese profecía, y entendiese todos los misterios y toda ciencia; y si tuviese toda la fe, de tal manera que traspasase los montes, y no tengo caridad, nada soy.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 3, 'Y si repartiese toda mi hacienda para dar de comer a pobres, y si entregase mi cuerpo para ser quemado, y no tengo caridad, de nada me sirve.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 4, 'La caridad es sufrida, es benigna; la caridad no tiene envidia, la caridad no hace sinrazón, no se ensancha;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 5, 'No es injuriosa, no busca lo suyo, no se irrita, no piensa el mal;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 6, 'No se huelga de la injusticia, mas se huelga de la verdad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 7, 'Todo lo sufre, todo lo cree, todo lo espera, todo lo soporta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 8, 'La caridad nunca deja de ser: mas las profecías se han de acabar, y cesarán las lenguas, y la ciencia ha de ser quitada;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 9, 'Porque en parte conocemos, y en parte profetizamos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 10, 'Mas cuando venga lo que es perfecto, entonces lo que es en parte será quitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 11, 'Cuando yo era niño, hablaba como niño, pensaba como niño, juzgaba como niño, mas cuando ya fuí hombre hecho, dejé lo que era de niño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 12, 'Ahora vemos por espejo, en obscuridad; mas entonces veremos cara á cara: ahora conozco en parte; mas entonces conoceré como soy conocido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 13, 13, 'Y ahora permanecen la fe, la esperanza, y la caridad, estas tres: empero la mayor de ellas es la caridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 1, 'SEGUID la caridad; y procurad los dones espirituales, mas sobre todo que profeticéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 2, 'Porque el que habla en lenguas, no habla á los hombres, sino á Dios; porque nadie le entiende, aunque en espíritu hable misterios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 3, 'Mas el que profetiza, habla á los hombres para edificación, y exhortación, y consolación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 4, 'El que habla lengua extraña, á sí mismo se edifica; mas el que porfetiza, edifica á la iglesia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 5, 'Así que, quisiera que todos vosotros hablaseis lenguas, empero más que profetizaseis: porque mayor es el que profetiza que el que habla lenguas, si también no interpretare, para que la iglesia tome edificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 6, 'Ahora pues, hermanos, si yo fuere á vosotros hablando lenguas, ¿qué os aprovecharé, si no os hablare, ó con revelación, ó con ciencia, ó con profecía, ó con doctrina?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 7, 'Ciertamente las cosas inanimadas que hacen sonidos, como la flauta ó la vihuela, si no dieren distinción de voces, ¿comó se sabrá lo que se tañe con la flauta, ó con la vihuela?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 8, 'Y si la trompeta diere sonido incierto, ¿quién se apercibirá á la batalla?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 9, 'Así también vosotros, si por la lengua no diereis palabra bien significante, ¿cómo se entenderá lo que se dice? porque hablaréis al aire.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 10, 'Tantos géneros de voces, por ejemplo, hay en el mundo, y nada hay mudo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 11, 'Mas si yo ignorare el valor de la voz, seré bárbaro al que habla, y el que habla será bárbaro para mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 12, 'Así también vosotros; pues que anheláis espirituales dones, procurad ser excelentes para la edificación de la iglesia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 13, 'Por lo cual, el que habla lengua extraña, pida que la interprete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 14, 'Porque si yo orare en lengua desconocida, mi espíritu ora; mas mi entendimiento es sin fruto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 15, '¿Qué pues? Oraré con el espíritu, mas oraré también con entendimiento; cantaré con el espíritu, mas cantaré también con entendimiento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 16, 'Porque si bendijeres con el espíritu, el que ocupa lugar de un mero particular, ¿cómo dirá amén á tu acción de gracias? pues no sabe lo que has dicho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 17, 'Porque tú, á la verdad, bien haces gracias; mas el otro no es edificado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 18, 'Doy gracias á Dios que hablo lenguas más que todos vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 19, 'Pero en la iglesia más quiero hablar cinco palabras con mi sentido, para que enseñe también á los otros, que diez mil palabras en lengua desconocida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 20, 'Hermanos, no seáis niños en el sentido, sino sed niños en la malicia: empero perfectos en el sentido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 21, 'En la ley está escrito: En otras lenguas y en otros labios hablaré á este pueblo; y ni aun así me oirán, dice el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 22, 'Así que, las lenguas por señal son, no á los fieles, sino á los infieles: mas la profecía, no á los infieles, sino á los fieles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 23, 'De manera que, si toda la iglesia se juntare en uno, y todos hablan lenguas, y entran indoctos ó infieles, ¿no dirán que estáis locos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 24, 'Mas si todos profetizan, y entra algún infiel ó indocto, de todos es convencido, de todos es juzgado;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 25, 'Lo oculto de su corazón se hace manifiesto: y así, postrándose sobre el rostro, adorará á Dios, declarando que verdaderamente Dios está en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 26, '¿Qué hay pues, hermanos? Cuando os juntáis, cada uno de vosotros tiene salmo, tiene doctrina, tiene lengua, tiene revelación, tiene interpretación: hagáse todo para edificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 27, 'Si hablare alguno en lengua extraña, sea esto por dos, ó á lo más tres, y por turno; mas uno interprete.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 28, 'Y si no hubiere intérprete, calle en la iglesia, y hable á sí mismo y á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 29, 'Asimismo, los profetas hablen dos ó tres, y los demás juzguen.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 30, 'Y si á otro que estuviere sentado, fuere revelado, calle el primero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 31, 'Porque podéis todos profetizar uno por uno, para que todos aprendan, y todos sean exhortados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 32, 'Y los espíritus de los que profetizaren, sujétense á los profetas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 33, 'Porque Dios no es Dios de disensión, sino de paz; como en todas las iglesias de los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 34, 'Vuestras mujeres callen en las congregaciones; porque no les es permitido hablar, sino que estén sujetas, como también la ley dice.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 35, 'Y si quieren aprender alguna cosa, pregunten en casa á sus maridos; porque deshonesta cosa es hablar una mujer en la congregación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 36, 'Qué, ¿ha salido de vosotros la palabra de Dios? ¿ó á vosotros solos ha llegado?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 37, 'Si alguno á su parecer, es profeta, ó espiritual, reconozca lo que os escribo, porque son mandamientos del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 38, 'Mas el que ignora, ignore.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 39, 'Así que, hermanos, procurad profetizar; y no impidáis el hablar lenguas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 14, 40, 'Empero hagáse todo decentemente y con orden.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 1, 'ADEMAS os declaro, hermanos, el evangelio que os he predicado, el cual también recibisteis, en el cual también perseveráis;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 2, 'Por el cual asimismo, si retenéis la palabra que os he predicado, sois salvos, si no creísteis en vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 3, 'Porque primeramente os he enseñado lo que asimismo recibí: Que Cristo fué muerto por nuestros pecados conforme á las Escrituras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 4, 'Y que fué sepultado, y que resucitó al tercer día, conforme á las Escrituras;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 5, 'Y que apareció á Cefas, y después á los doce.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 6, 'Después apareció á más de quinientos hermanos juntos; de los cuales muchos viven aún, y otros son muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 7, 'Después apareció á Jacobo; después á todos los apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 8, 'Y el postrero de todos, como á un abortivo, me apareció á mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 9, 'Porque yo soy el más pequeño de los apóstoles, que no soy digno de ser llamado apóstol, porque perseguí la iglesia de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 10, 'Empero por la gracia de Dios soy lo que soy: y su gracia no ha sido en vano para conmigo; antes he trabajado más que todos ellos: pero no yo, sino la gracia de Dios que fué conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 11, 'Porque, ó sea yo ó sean ellos, así predicamos, y así habéis creído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 12, 'Y si Cristo es predicado que resucitó de los muertos ¿cómo dicen algunos entre vosotros que no hay resurrección de muertos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 13, 'Porque si no hay resurrección de muertos, Cristo tampoco resucitó:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 14, 'Y si Cristo no resucitó, vana es entonces nuestra predicación, vana es también vuestra fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 15, 'Y aun somos hallados falsos testigos de Dios; porque hemos testificado de Dios que él haya levantado á Cristo; al cual no levantó, si en verdad los muertos no resucitan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 16, 'Porque si los muertos no resucitan, tampoco Cristo resucitó.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 17, 'Y si Cristo no resucitó, vuestra fe es vana; aun estáis en vuestros pecados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 18, 'Entonces también los que durmieron en Cristo son perdidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 19, 'Si en esta vida solamente esperamos en Cristo, los más miserables somos de todos los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 20, 'Mas ahora Cristo ha resucitado de los muertos; primicias de los que durmieron es hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 21, 'Porque por cuanto la muerte entró por un hombre, también por un hombre la resurrección de los muertos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 22, 'Porque así como en Adam todos mueren, así también en Cristo todos serán vivificados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 23, 'Mas cada uno en su orden: Cristo las primicias; luego los que son de Cristo, en su venida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 24, 'Luego el fin; cuando entregará el reino á Dios y al Padre, cuando habrá quitado todo imperio, y toda potencia y potestad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 25, 'Porque es menester que él reine, hasta poner á todos sus enemigos debajo de sus pies.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 26, 'Y el postrer enemigo que será deshecho, será la muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 27, 'Porque todas las cosas sujetó debajo de sus pies. Y cuando dice: Todas las cosas son sujetadas á él, claro está exceptuado aquel que sujetó á él todas las cosas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 28, 'Mas luego que todas las cosas le fueren sujetas, entonces también el mismo Hijo se sujetará al que le sujetó á él todas las cosas, para que Dios sea todas las cosas en todos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 29, 'De otro modo, ¿qué harán los que se bautizan por los muertos, si en ninguna manera los muertos resucitan? ¿Por qué pues se bautizan por los muertos?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 30, '¿Y por qué nosotros peligramos á toda hora?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 31, 'Sí, por la gloria que en orden á vosotros tengo en Cristo Jesús Señor nuestro, cada día muero.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 32, 'Si como hombre batallé en Efeso contra las bestias, ¿qué me aprovecha? Si los muertos no resucitan, comamos y bebamos, que mañana moriremos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 33, 'No erréis: las malas conversaciones corrompen las buenas costumbres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 34, 'Velad debidamente, y no pequéis; porque algunos no conocen á Dios: para vergüenza vuestra hablo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 35, 'Mas dirá alguno: ¿Cómo resucitarán los muertos? ¿Con qué cuerpo vendrán?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 36, 'Necio, lo que tú siembras no se vivifica, si no muriere antes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 37, 'Y lo que siembras, no siembras el cuerpo que ha de salir, sino el grano desnudo, acaso de trigo, ó de otro grano:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 38, 'Mas Dios le da el cuerpo como quiso, y á cada simiente su propio cuerpo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 39, 'Toda carne no es la misma carne; mas una carne ciertamente es la de los hombres, y otra carne la de los animales, y otra la de los peces, y otra la de las aves.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 40, 'Y cuerpos hay celestiales, y cuerpos terrestres; mas ciertamente una es la gloria de los celestiales, y otra la de los terrestres:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 41, 'Otra es la gloria del sol, y otra la gloria de la luna, y otra la gloria de las estrellas: porque una estrella es diferente de otra en gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 42, 'Así también es la resurrección de los muertos. Se siembra en corrupción se levantará en incorrupción;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 43, 'Se siembra en vergüenza, se levantará con gloria; se siembra en flaqueza, se levantará con potencia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 44, 'Se siembra cuerpo animal, resucitará espiritual cuerpo. Hay cuerpo animal, y hay cuerpo espiritual.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 45, 'Así también está escrito: Fué hecho el primer hombre Adam en ánima viviente; el postrer Adam en espíritu vivificante.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 46, 'Mas lo espiritual no es primero, sino lo animal; luego lo espiritual.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 47, 'El primer hombre, es de la tierra, terreno: el segundo hombre que es el Señor, es del cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 48, 'Cual el terreno, tales también los terrenos; y cual el celestial, tales también los celestiales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 49, 'Y como trajimos la imagen del terreno, traeremos también la imagen del celestial.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 50, 'Esto empero digo, hermanos: que la carne y la sangre no pueden heredar el reino de Dios; ni la corrupción hereda la incorrupción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 51, 'He aquí, os digo un misterio: Todos ciertamente no dormiremos, mas todos seremos transformados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 52, 'En un momento, en un abrir de ojo, á la final trompeta; porque será tocada la trompeta, y los muertos serán levantados sin corrupción, y nosotros seremos transformados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 53, 'Porque es menester que esto corruptible sea vestido de incorrupción, y esto mortal sea vestido de inmortalidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 54, 'Y cuando esto corruptible fuere vestido de incorrupción, y esto mortal fuere vestido de inmortalidad, entonces se efectuará la palabra que está escrita: Sorbida es la muerte con victoria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 55, '¿Dónde está, oh muerte, tu aguijón? ¿dónde, oh sepulcro, tu victoria?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 56, 'Ya que el aguijón de la muerte es el pecado, y la potencia del pecado, la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 57, 'Mas á Dios gracias, que nos da la victoria por el Señor nuestro Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 15, 58, 'Así que, hermanos míos amados, estad firmes y constantes, creciendo en la obra del Señor siempre, sabiendo que vuestro trabajo en el Señor no es vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 1, 'CUANTO á la colecta para los santos, haced vosotros también de la manera que ordené en las iglesias de Galacia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 2, 'Cada primer día de la semana cada uno de vosotros aparte en su casa, guardando lo que por la bondad de Dios pudiere; para que cuando yo llegare, no se hagan entonces colectas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 3, 'Y cuando habré llegado, los que aprobareis por cartas, á éstos enviaré que lleven vuestro beneficio á Jerusalem.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 4, 'Y si fuere digno el negocio de que yo también vaya, irán conmigo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 5, 'Y á vosotros iré, cuando hubiere pasado por Macedonia, porque por Macedonia tengo de pasar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 6, 'Y podrá ser que me quede con vosotros, ó invernaré también, para que vosotros me llevéis á donde hubiere de ir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 7, 'Porque no os quiero ahora ver de paso; porque espero estar con vosotros algún tiempo, si el Señor lo permitiere.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 8, 'Empero estaré en Efeso hasta Pentecostés;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 9, 'Porque se me ha abierto puerta grande y eficaz, y muchos son los adversarios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 10, 'Y si llegare Timoteo, mirad que esté con vosotros seguramente; porque la obra del Señor hace también como yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 11, 'Por tanto, nadie le tenga en poco; antes, llevadlo en paz, para que venga á mí: porque lo espero con los hermanos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 12, 'Acerca del hermano Apolos, mucho le he rogado que fuese á vosotros con los hermanos; mas en ninguna manera tuvo voluntad de ir por ahora; pero irá cuando tuviere oportunidad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 13, 'Velad, estad firmes en la fe; portaos varonilmente, y esforzaos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 14, 'Todas vuestras cosas sean hechas con caridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 15, 'Y os ruego, hermanos, (ya sabéis que la casa de Estéfanas es las primicias de Acaya, y que se han dedicado al ministerio de los santos,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 16, 'Que vosotros os sujetéis á los tales, y á todos los que ayudan y trabajan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 17, 'Huélgome de la venida de Estéfanas y de Fortunato y de Achâico: porque éstos suplieron lo que á vosotros faltaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 18, 'Porque recrearon mi espíritu y el vuestro: reconoced pues á los tales.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 19, 'Las iglesias de Asia os saludan. Os saludan mucho en el Señor Aquila y Priscila, con la iglesia que está en su casa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 20, 'Os saludan todos los hermanos. Saludaos los unos á los otros con ósculo santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 21, 'La salutación de mí, Pablo, de mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 22, 'El que no amare al Señor Jesucristo, sea anatema. Maranatha.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 23, 'La gracia del Señor Jesucristo sea con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('1CO', '1 Corintios', 16, 24, 'Mi amor en Cristo Jesús sea con todos vosotros. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 1, 'PABLO, apóstol de Jesucristo por la voluntad de Dios, y Timoteo el hermano, á la iglesia de Dios que está en Corinto, juntamente con todos los santos que están por toda la Acaya:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 2, 'Gracia y paz á vosotros de Dios nuestro Padre, y del Señor Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 3, 'Bendito sea el Dios y Padre del Señor Jesucristo, el Padre de misericordias, y el Dios de toda consolación,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 4, 'El cual nos consuela en todas nuestras tribulaciones, para que podamos también nosotros consolar á los que están en cualquiera angustia, con la consolación con que nosotros somos consolados de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 5, 'Porque de la manera que abundan en nosotros las aflicciones de Cristo, así abunda también por el mismo Cristo nuestra consolación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 6, 'Mas si somos atribulados, es por vuestra consolación y salud; la cual es obrada en el sufrir las mismas aflicciones que nosotros también padecemos: ó si somos consolados, es por vuestra consolación y salud;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 7, 'Y nuestra esperanza de vosotros es firme; estando ciertos que como sois compañeros de las aflicciones, así también lo sois de la consolación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 8, 'Porque hermanos, no queremos que ignoréis de nuestra tribulación que nos fué hecha en Asia; que sobremanera fuimos cargados sobre nuestras fuerzas de tal manera que estuviésemos en duda de la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 9, 'Mas nosotros tuvimos en nosotros mismos respuesta de muerte, para que no confiemos en nosotros mismos, sino en Dios que levanta los muertos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 10, 'El cual nos libró y libra de tanta muerte; en el cual esperamos que aun nos librará;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 11, 'Ayudándonos también vosotros con oración por nosotros, para que por la merced hecha á nos por respeto de muchos, por muchos sean hechas gracias por nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 12, 'Porque nuestra gloria es esta: el testimonio de nuestra conciencia, que con simplicidad y sinceridad de Dios, no con sabiduría carnal, mas con la gracia de Dios, hemos conversado en el mundo, y muy más con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 13, 'Porque no os escribimos otras cosas de las que leéis, ó también conocéis: y espero que aun hasta el fin las conoceréis:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 14, 'Como también en parte habéis conocido que somos vuestra gloria, así como también vosotros la nuestra, para el día del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 15, 'Y con esta confianza quise primero ir á vosotros, para que tuvieseis una segunda gracia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 16, 'Y por vosotros pasar á Macedonia, y de Macedonia venir otra vez á vosotros, y ser vuelto de vosotros á Judea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 17, 'Así que, pretendiendo esto, ¿usé quizá de liviandad? ó lo que pienso hacer, ¿piénsolo según la carne, para que haya en mí Sí y No?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 18, 'Antes, Dios fiel sabe que nuestra palabra para con vosotros no es Sí y No.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 19, 'Porque el Hijo de Dios, Jesucristo, que por nosotros ha sido entre vosotros predicado, por mí y Silvano y Timoteo, no ha sido Sí y No; mas ha sido Sí en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 20, 'Porque todas las promesas de Dios son en él Sí, y en él Amén, por nosotros á gloria de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 21, 'Y el que nos confirma con vosotros en Cristo, y el que nos ungió, es Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 22, 'El cual también nos ha sellado, y dado la prenda del Espíritu en nuestros corazones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 23, 'Mas yo llamo á Dios por testigo sobre mi alma, que por ser indulgente con vosotros no he pasado todavía á Corinto.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 1, 24, 'No que nos enseñoreemos de vuestra fe, mas somos ayudadores de vuestro gozo: porque por la fe estáis firmes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 1, 'ESTO pues determiné para conmigo, no venir otra vez á vosotros con tristeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 2, 'Porque si yo os contristo, ¿quién será luego el que me alegrará, sino aquel á quien yo contristare?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 3, 'Y esto mismo os escribí, porque cuando llegare no tenga tristeza sobre tristeza de los que me debiera gozar; confiando en vosotros todos que mi gozo es el de todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 4, 'Porque por la mucha tribulación y angustia del corazón os escribí con muchas lágrimas; no para que fueseis contristados, mas para que supieseis cuánto más amor tengo para con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 5, 'Que si alguno me contristó, no me contristó á mí, sino en parte, por no cargaros, á todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 6, 'Bástale al tal esta reprensión hecha de muchos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 7, 'Así que, al contrario, vosotros más bien lo perdonéis y consoléis, porque no sea el tal consumido de demasiada tristeza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 8, 'Por lo cual os ruego que confirméis el amor para con él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 9, 'Porque también por este fin os escribí, para tener experiencia de vosotros si sois obedientes en todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 10, 'Y al que vosotros perdonareis, yo también: porque también yo lo que he perdonado, si algo he perdonado, por vosotros lo he hecho en persona de Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 11, 'Porque no seamos engañados de Satanás: pues no ignoramos sus maquinaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 12, 'Cuando vine á Troas para el evangelio de Cristo, aunque me fué abierta puerta en el Señor,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 13, 'No tuve reposo en mi espíritu, por no haber hallado á Tito mi hermano: así, despidiéndome de ellos, partí para Macedonia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 14, 'Mas á Dios gracias, el cual hace que siempre triunfemos en Cristo Jesús, y manifiesta el olor de su conocimiento por nosotros en todo lugar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 15, 'Porque para Dios somos buen olor de Cristo en los que se salvan, y en los que se pierden:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 16, 'A éstos ciertamente olor de muerte para muerte; y á aquéllos olor de vida para vida. Y para estas cosas ¿quién es suficiente?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 2, 17, 'Porque no somos como muchos, mercaderes falsos de la palabra de Dios: antes con sinceridad, como de Dios, delante de Dios, hablamos en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 1, '¿COMENZAMOS otra vez á alabarnos á nosotros mismos? ¿ó tenemos necesidad, como algunos, de letras de recomendación para vosotros, ó de recomendación de vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 2, 'Nuestras letras sois vosotros, escritas en nuestros corazones, sabidas y leídas de todos los hombres;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 3, 'Siendo manifiesto que sois letra de Cristo administrada de nosotros, escrita no con tinta, mas con el Espíritu del Dios vivo; no en tablas de piedra, sino en tablas de carne del corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 4, 'Y tal confianza tenemos por Cristo para con Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 5, 'No que seamos suficientes de nosotros mismos para pensar algo como de nosotros mismos, sino que nuestra suficiencia es de Dios;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 6, 'El cual asimismo nos hizo ministros suficientes de un nuevo pacto: no de la letra, mas del espíritu; porque la letra mata, mas el espíritu vivifica.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 7, 'Y si el ministerio de muerte en la letra grabado en piedras, fué con gloria, tanto que los hijos de Israel no pudiesen poner los ojos en la faz de Moisés á causa de la gloria de su rostro, la cual había de perecer,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 8, '¿Cómo no será más bien con gloria el ministerio del espíritu?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 9, 'Porque si el ministerio de condenación fué con gloria, mucho más abundará en gloria el ministerio de justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 10, 'Porque aun lo que fué glorioso, no es glorioso en esta parte, en comparación de la excelente gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 11, 'Porque si lo que perece tuvo gloria, mucho más será en gloria lo que permanece.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 12, 'Así que, teniendo tal esperanza, hablamos con mucha confianza;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 13, 'Y no como Moisés, que ponía un velo sobre su faz, para que los hijos de Israel no pusiesen los ojos en el fin de lo que había de ser abolido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 14, 'Empero los sentidos de ellos se embotaron; porque hasta el día de hoy les queda el mismo velo no descubierto en la lección del antiguo testamento, el cual por Cristo es quitado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 15, 'Y aun hasta el día de hoy, cuando Moisés es leído, el velo está puesto sobre el corazón de ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 16, 'Mas cuando se convirtieren al Señor, el velo se quitará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 17, 'Porque el Señor es el Espíritu; y donde hay el Espíritu del Señor, allí hay libertad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 3, 18, 'Por tanto, nosotros todos, mirando á cara descubierta como en un espejo la gloria del Señor, somos transformados de gloria en gloria en la misma semejanza, como por el Espíritu del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 1, 'POR lo cual teniendo nosotros esta administración según la misericordia que hemos alcanzado, no desmayamos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 2, 'Antes quitamos los escondrijos de vergüenza, no andando con astucia, ni adulterando la palabra de Dios, sino por manifestación de la verdad encomendándonos á nosotros mismos á toda conciencia humana delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 3, 'Que si nuestro evangelio está aún encubierto, entre los que se pierden está encubierto:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 4, 'En los cuales el dios de este siglo cegó los entendimientos de los incrédulos, para que no les resplandezca la lumbre del evangelio de la gloria de Cristo, el cual es la imagen de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 5, 'Porque no nos predicamos á nosotros mismos, sino á Jesucristo, el Señor; y nosotros vuestros siervos por Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 6, 'Porque Dios, que mandó que de las tinieblas resplandeciese la luz, es el que resplandeció en nuestros corazones, para iluminación del conocimiento de la gloria de Dios en la faz de Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 7, 'Tenemos empero este tesoro en vasos de barro, para que la alteza del poder sea de Dios, y no de nosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 8, 'Estando atribulados en todo, mas no angustiados; en apuros, mas no desesperamos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 9, 'Perseguidos, mas no desamparados; abatidos, mas no perecemos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 10, 'Llevando siempre por todas partes la muerte de Jesús en el cuerpo, para que también la vida de Jesús sea manifestada en nuestros cuerpos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 11, 'Porque nosotros que vivimos, siempre estamos entregados á muerte por Jesús, para que también la vida de Jesús sea manifestada en nuestra carne mortal.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 12, 'De manera que la muerte obra en nosotros, y en vosotros la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 13, 'Empero teniendo el mismo espíritu de fe, conforme á lo que está escrito: Creí, por lo cual también hablé: nosotros también creemos, por lo cual también hablamos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 14, 'Estando ciertos que el que levantó al Señor Jesús, á nosotros también nos levantará por Jesús, y nos pondrá con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 15, 'Porque todas estas cosas padecemos por vosotros, para que abundando la gracia por muchos, en el hacimiento de gracias sobreabunde á gloria de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 16, 'Por tanto, no desmayamos: antes aunque este nuestro hombre exterior se va desgastando, el interior empero se renueva de día en día.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 17, 'Porque lo que al presente es momentáneo y leve de nuestra tribulación, nos obra un sobremanera alto y eterno peso de gloria;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 4, 18, 'No mirando nosotros á las cosas que se ven, sino á las que no se ven: porque las cosas que se ven son temporales, mas las que no se ven son eternas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 1, 'PORQUE sabemos, que si la casa terrestre de nuestra habitación se deshiciere, tenemos de Dios un edificio, una casa no hecha de manos, eterna en los cielos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 2, 'Y por esto también gemimos, deseando ser sobrevestidos de aquella nuestra habitación celestial;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 3, 'Puesto que en verdad habremos sido hallados vestidos, y no desnudos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 4, 'Porque asimismo los que estamos en este tabernáculo, gemimos agravados; porque no quisiéramos ser desnudados; sino sobrevestidos, para que lo mortal sea absorbido por la vida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 5, 'Mas el que nos hizo para esto mismo, es Dios; el cual nos ha dado la prenda del Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 6, 'Así que vivimos confiados siempre, y sabiendo, que entre tanto que estamos en el cuerpo, peregrinamos ausentes del Señor;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 7, '(Porque por fe andamos, no por vista;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 8, 'Mas confiamos, y más quisiéramos partir del cuerpo, y estar presentes al Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 9, 'Por tanto procuramos también, ó ausentes, ó presentes, serle agradables:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 10, 'Porque es menester que todos nosotros parezcamos ante el tribunal de Cristo, para que cada uno reciba según lo que hubiere hecho por medio del cuerpo, ora sea bueno ó malo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 11, 'Estando pues poseídos del temor del Señor, persuadimos á los hombres, mas á Dios somos manifiestos; y espero que también en vuestras conciencias somos manifiestos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 12, 'No nos encomendamos pues otra vez á vosotros, sino os damos ocasión de gloriaros por nosotros, para que tengáis qué responder contra los que se glorían en las apariencias, y no en el corazón.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 13, 'Porque si loqueamos, es para Dios; y si estamos en seso, es para vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 14, 'Porque el amor de Cristo nos constriñe, pensando esto: Que si uno murió por todos, luego todos son muertos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 15, 'Y por todos murió, para que los que viven, ya no vivan para sí, mas para aquel que murió y resucitó por ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 16, 'De manera que nosotros de aquí adelante á nadie conocemos según la carne: y aun si á Cristo conocimos según la carne, empero ahora ya no le conocemos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 17, 'De modo que si alguno está en Cristo, nueva criatura es: las cosas viejas pasaron; he aquí todas son hechas nuevas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 18, 'Y todo esto es de Dios, el cual nos reconcilió á sí por Cristo; y nos dió el ministerio de la reconciliación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 19, 'Porque ciertamente Dios estaba en Cristo reconciliando el mundo á sí, no imputándole sus pecados, y puso en nosotros la palabra de la reconciliación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 20, 'Así que, somos embajadores en nombre de Cristo, como si Dios rogase por medio nuestro; os rogamos en nombre de Cristo: Reconciliaos con Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 5, 21, 'Al que no conoció pecado, hizo pecado por nosotros, para que nosotros fuésemos hechos justicia de Dios en él.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 1, 'Y ASI nosotros, como ayudadores juntamente con él, os exhortamos también á que no recibáis en vano la gracia de Dios,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 2, 'En tiempo aceptable te he oído, Y en día de salud te he socorrido: he aquí ahora el tiempo aceptable; he aquí ahora el día de salud:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 3, 'No dando á nadie ningún escándalo, porque el ministerio nuestro no sea vituperado:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 4, 'Antes habiéndonos en todas cosas como ministros de Dios, en mucha paciencia, en tribulaciones, en necesidades, en angustias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 5, 'En azotes, en cárceles, en alborotos, en trabajos, en vigilias, en ayunos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 6, 'En castidad, en ciencia, en longanimidad, en bondad, en Espíritu Santo, en amor no fingido;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 7, 'En palabra de verdad, en potencia de Dios, en armas de justicia á diestro y á siniestro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 8, 'Por honra y por deshonra, por infamia y por buena fama; como engañadores, mas hombres de verdad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 9, 'Como ignorados, mas conocidos; como muriendo, mas he aquí vivimos; como castigados, mas no muertos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 10, 'Como doloridos, mas siempre gozosos; como pobres, mas enriqueciendo á muchos; como no teniendo nada, mas poseyéndolo todo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 11, 'Nuestra boca está abierta á vosotros, oh Corintios: nuestro corazón es ensanchado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 12, 'No estáis estrechos en nosotros, mas estáis estrechos en vuestras propias entrañas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 13, 'Pues, para corresponder al propio modo (como á hijos hablo), ensanchaos también vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 14, 'No os juntéis en yugo con los infieles: porque ¿qué compañía tienes la justicia con la injusticia? ¿y qué comunión la luz con las tinieblas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 15, '¿Y qué concordia Cristo con Belial? ¿ó qué parte el fiel con el infiel?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 16, '¿Y qué concierto el templo de Dios con los ídolos? porque vosotros sois el templo del Dios viviente, como Dios dijo: Habitaré y andaré en ellos; y seré el Dios de ellos, y ellos serán mi pueblo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 17, 'Por lo cual Salid de en medio de ellos, y apartaos, dice el Señor, Y no toquéis lo inmundo; Y yo os recibiré,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 6, 18, 'Y seré á vosotros Padre, Y vosotros me seréis á mí hijos é hijas, dice el Señor Todopoderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 1, 'ASI que, amados, pues tenemos tales promesas, limpiémonos de toda inmundicia de carne y de espíritu, perfeccionando la santificación en temor de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 2, 'Admitidnos: á nadie hemos injuriado, á nadie hemos corrompido, á nadie hemos engañado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 3, 'No para condenar os lo digo; que ya he dicho antes que estáis en nuestros corazones, para morir y para vivir juntamente.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 4, 'Mucha confianza tengo de vosotros, tengo de vosotros mucha gloria; lleno estoy de consolación, sobreabundo de gozo en todas nuestras tribulaciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 5, 'Porque aun cuando vinimos á Macedonia, ningún reposo tuvo nuestra carne; antes, en todo fuimos atribulados: de fuera, cuestiones; de dentro, temores.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 6, 'Mas Dios, que consuela á los humildes, nos consoló con la venida de Tito:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 7, 'Y no sólo con su venida, sino también con la consolación con que él fué consolado acerca de vosotros, haciéndonos saber vuestro deseo grande, vuestro lloro, vuestro celo por mí, para que así me gozase más.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 8, 'Porque aunque os contristé por la carta, no me arrepiento, bien que me arrepentí; porque veo que aquella carta, aunque por algún tiempo os contristó,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 9, 'Ahora me gozo, no porque hayáis sido contristados, sino porque fuisteis contristados para arrepentimiento; porque habéis sido contristados según Dios, para que ninguna pérdida padecieseis por nuestra parte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 10, 'Porque el dolor que es según Dios, obra arrepentimiento saludable, de que no hay que arrepentirse; mas el dolor del siglo obra muerte.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 11, 'Porque he aquí, esto mismo que según Dios fuisteis contristados, cuánta solicitud ha obrado en vosotros, y aun defensa, y aun enojo, y aun temor, y aun gran deseo, y aun celo, y aun vindicación. En todo os habéis mostrado limpios en el negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 12, 'Así que, aunque os escribí, no fué por causa del que hizo la injuria, ni por causa del que la padeció, mas para que os fuese manifiesta nuestra solicitud que tenemos por vosotros delante de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 13, 'Por tanto, tomamos consolación de vuestra consolación: empero mucho más nos gozamos por el gozo de Tito, que haya sido recreado su espíritu de todos vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 14, 'Pues si algo me he gloriado para con él de vosotros, no he sido avergonzado; antes, como todo lo que habíamos dicho de vosotros era con verdad, así también nuestra gloria delante de Tito fué hallada verdadera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 15, 'Y sus entrañas son más abundantes para con vosotros, cuando se acuerda de la obediencia de todos vosotros, de cómo lo recibisteis con temor y temblor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 7, 16, 'Me gozo de que en todo estoy confiado de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 1, 'ASIMISMO, hermanos, os hacemos saber la gracia de Dios que ha sido dada á las iglesias de Macedonia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 2, 'Que en grande prueba de tribulación, la abundancia de su gozo y su profunda pobreza abundaron en riquezas de su bondad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 3, 'Pues de su grado han dado conforme á sus fuerzas, yo testifico, y aun sobre sus fuerzas;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 4, 'Pidiéndonos con muchos ruegos, que aceptásemos la gracia y la comunicación del servicio para los santos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 5, 'Y no como lo esperábamos, mas aun á sí mismos se dieron primeramente al Señor, y á nosotros por la voluntad de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 6, 'De manera que exhortamos á Tito, que como comenzó antes, así también acabe esta gracia entre vosotros también.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 7, 'Por tanto, como en todo abundáis, en fe, y en palabra, y en ciencia, y en toda solicitud, y en vuestro amor para con nosotros, que también abundéis en esta gracia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 8, 'No hablo como quien manda, sino para poner á prueba, por la eficacia de otros, la sinceridad también de la caridad vuestra.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 9, 'Porque ya sabéis la gracia de nuestro Señor Jesucristo, que por amor de vosotros se hizo pobre, siendo rico; para que vosotros con su pobreza fueseis enriquecidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 10, 'Y en esto doy mi consejo; porque esto os conviene á vosotros, que comenzasteis antes, no sólo á hacerlo, mas aun á quererlo desde el año pasado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 11, 'Ahora pues, llevad también á cabo el hecho, para que como estuvisteis prontos á querer, así también lo estéis en cumplir conforme á lo que tenéis.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 12, 'Porque si primero hay la voluntad pronta, será acepta por lo que tiene, no por lo que no tiene.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 13, 'Porque no digo esto para que haya para otros desahogo, y para vosotros apretura;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 14, 'Sino para que en este tiempo, con igualdad, vuestra abundancia supla la falta de ellos, para que también la abundancia de ellos supla vuestra falta, porque haya igualdad;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 15, 'Como está escrito: El que recogió mucho, no tuvo más; y el que poco, no tuvo menos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 16, 'Empero gracias á Dios que dió la misma solicitud por vosotros en el corazón de Tito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 17, 'Pues á la verdad recibió la exhortación; mas estando también muy solícito, de su voluntad partió para vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 18, 'Y enviamos juntamente con él al hermano cuya alabanza en el evangelio es por todas las iglesias;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 19, 'Y no sólo esto, mas también fué ordenado por las iglesias el compañero de nuestra peregrinación para llevar esta gracia, que es administrada de nosotros para gloria del mismo Señor, y para demostrar vuestro pronto ánimo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 20, 'Evitando que nadie nos vitupere en esta abundancia que ministramos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 21, 'Procurando las cosas honestas, no sólo delante del Señor, mas aun delante de los hombres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 22, 'Enviamos también con ellos á nuestro hermano, al cual muchas veces hemos experimentado diligente, mas ahora mucho más con la mucha confianza que tiene en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 23, 'Ora en orden á Tito, es mi compañero y coadjutor para con vosotros; ó acerca de nuestros hermanos, los mensajeros son de las iglesias, y la gloria de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 8, 24, 'Mostrad pues, para con ellos á la faz de las iglesias la prueba de vuestro amor, y de nuestra gloria acerca de vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 1, 'PORQUE cuanto á la suministración para los santos, por demás me es escribiros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 2, 'Pues conozco vuestro pronto ánimo, del cual me glorío yo entre los de Macedonia, que Acaya está apercibida desde el año pasado; y vuestro ejemplo ha estimulado á muchos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 3, 'Mas he enviado los hermanos, porque nuestra gloria de vosotros no sea vana en esta parte; para que, como lo he dicho, estéis apercibidos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 4, 'No sea que, si vinieren conmigo Macedonios, y os hallaren desapercibidos, nos avergoncemos nosotros, por no decir vosotros, de este firme gloriarnos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 5, 'Por tanto, tuve por cosa necesaria exhortar á los hermanos que fuesen primero á vosotros, y apresten primero vuestra bendición antes prometida para que esté aparejada como de bendición, y no como de mezquindad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 6, 'Esto empero digo: El que siembra escasamente, también segará escasamente; y el que siembra en bendiciones, en bendiciones también segará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 7, 'Cada uno dé como propuso en su corazón: no con tristeza, ó por necesidad; porque Dios ama el dador alegre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 8, 'Y poderoso es Dios para hacer que abunde en vosotros toda gracia; á fin de que, teniendo siempre en todas las cosas todo lo que basta, abundéis para toda buena obra:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 9, 'Como está escrito: Derramó, dió á los pobres; Su justicia permanece para siempre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 10, 'Y el que da simiente al que siembra, también dará pan para comer, y multiplicará vuestra sementera, y aumentará los crecimientos de los frutos de vuestra justicia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 11, 'Para que estéis enriquecidos en todo para toda bondad, la cual obra por nosotros hacimiento de gracias á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 12, 'Porque la suministración de este servicio, no solamente suple lo que á los santos falta, sino también abunda en muchos hacimientos de gracias á Dios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 13, 'Que por la experiencia de esta suministración glorifican á Dios por la obediencia que profesáis al evangelio de Cristo, y por la bondad de contribuir para ellos y para todos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 14, 'Asimismo por la oración de ellos á favor vuestro, los cuales os quieren á causa de la eminente gracia de Dios en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 9, 15, 'Gracias á Dios por su don inefable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 1, 'EMPERO yo Pablo, os ruego por la mansedumbre y modestia de Cristo, yo que presente ciertamente soy bajo entre vosotros, mas ausente soy confiado entre vosotros:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 2, 'Ruego pues, que cuando estuviere presente, no tenga que ser atrevido con la confianza con que estoy en ánimo de ser resuelto para con algunos, que nos tienen como si anduviésemos según la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 3, 'Pues aunque andamos en la carne, no militamos según la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 4, '(Porque las armas de nuestra milicia no son carnales, sino poderosas en Dios para la destrucción de fortalezas;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 5, 'Destruyendo consejos, y toda altura que se levanta contra la ciencia de Dios, y cautivando todo intento á la obediencia, de Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 6, 'Y estando prestos para castigar toda desobediencia, cuando vuestra obediencia fuere cumplida.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 7, 'Miráis las cosas según la apariencia. Si alguno está confiado en sí mismo que es de Cristo, esto también piense por sí mismo, que como él es de Cristo, así también nosotros somos de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 8, 'Porque aunque me glorié aun un poco de nuestra potestad (la cual el Señor nos dió para edificación y no para vuestra destrucción), no me avergonzaré;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 9, 'Porque no parezca como que os quiero espantar por cartas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 10, 'Porque á la verdad, dicen, las cartas son graves y fuertes; mas la presencia corporal flaca, y la palabra menospreciable.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 11, 'Esto piense el tal, que cuales somos en la palabra por cartas estando ausentes, tales seremos también en hechos, estando presentes.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 12, 'Porque no osamos entremeternos ó compararnos con algunos que se alaban á sí mismos: mas ellos, midiéndose á sí mismos por sí mismos, y comparándose consigo mismos no son juiciosos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 13, 'Nosotros empero, no nos gloriaremos fuera de nuestra medida, sino conforme á la medida de la regla, de la medida que Dios nos repartió, para llegar aun hasta vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 14, 'Porque no nos extendemos sobre nuestra medida, como si no llegásemos hasta vosotros: porque también hasta vosotros hemos llegado en el evangelio de Cristo:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 15, 'No gloriándonos fuera de nuestra medida en trabajos ajenos; mas teniendo esperanza del crecimiento de vuestra fe, que seremos muy engrandecidos entre vosotros, conforme á nuestra regla.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 16, 'Y que anunciaremos el evangelio en los lugares más allá de vosotros, sin entrar en la medida de otro para gloriarnos en lo que ya estaba aparejado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 17, 'Mas el que se gloría, gloríese en el Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 10, 18, 'Porque no el que se alaba á sí mismo, el tal es aprobado; mas aquel á quien Dios alaba.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 1, 'OJALA toleraseis un poco mi locura; empero toleradme.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 2, 'Pues que os celo con celo de Dios; porque os he desposado á un marido, para presentaros como una virgen pura á Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 3, 'Mas temo que como la serpiente engaño á Eva con su astucia, sean corrompidos así vuestros sentidos en alguna manera, de la simplicidad que es en Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 4, 'Porque si el que viene, predicare otro Jesús que el que hemos predicado, ó recibiereis otro espíritu del que habéis recibido, ú otro evangelio del que habéis aceptado, lo sufrierais bien.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 5, 'Cierto pienso que en nada he sido inferior á aquellos grandes apóstoles.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 6, 'Porque aunque soy basto en la palabra, empero no en la ciencia: mas en todo somos ya del todo manifiestos á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 7, '¿Pequé yo humillándome á mí mismo, para que vosotros fueseis ensalzados, porque os he predicado el evangelio de Dios de balde?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 8, 'He despojado las otras iglesias, recibiendo salario para ministraros á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 9, 'Y estando con vosotros y teniendo necesidad, á ninguno fuí carga; porque lo que me faltaba, suplieron los hermanos que vinieron de Macedonia: y en todo me guardé de seros gravoso, y me guardaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 10, 'Es la verdad de Cristo en mí, que esta gloria no me será cerrada en las partes de Acaya.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 11, '¿Por qué? ¿porque no os amo? Dios lo sabe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 12, 'Mas lo que hago, haré aún, para cortar la ocasión de aquellos que la desean, á fin de que en aquello que se glorían, sean hallados semejantes á nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 13, 'Porque éstos son falsos apóstoles, obreros fraudulentos, trasfigurándose en apóstoles de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 14, 'Y no es maravilla, porque el mismo Satanás se transfigura en ángel de luz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 15, 'Así que, no es mucho si también sus ministros se transfiguran como ministros de justicia; cuyo fin será conforme á sus obras.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 16, 'Otra vez digo: Que nadie me estime ser loco; de otra manera, recibidme como á loco, para que aun me gloríe yo un poquito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 17, 'Lo que hablo, no lo hablo según el Señor, sino como en locura, con esta confianza de gloria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 18, 'Pues que muchos se glorían según la carne, también yo me gloriaré.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 19, 'Porque de buena gana toleráis los necios, siendo vosotros sabios:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 20, 'Porque toleráis si alguno os pone en servidumbre, si alguno os devora, si alguno toma, si alguno se ensalza, si alguno os hiere en la cara.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 21, 'Dígolo cuanto á la afrenta, como si nosotros hubiésemos sido flacos. Empero en lo que otro tuviere osadía (hablo con locura), también yo tengo osadía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 22, '¿Son Hebreos? yo también. ¿Son Israelitas? yo también. ¿Son simiente de Abraham? también yo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 23, '¿Son ministros de Cristo? (como poco sabio hablo) yo más: en trabajos más abundante; en azotes sin medida; en cárceles más; en muertes, muchas veces.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 24, 'De los judíos cinco veces he recibido cuarenta azotes menos uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 25, 'Tres veces he sido azotado con varas; una vez apedreado; tres veces he padecido naufragio; una noche y un día he estado en lo profundo de la mar;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 26, 'En caminos muchas veces, peligros de ríos, peligros de ladrones, peligros de los de mi nación, peligros de los Gentiles, peligros en la ciudad, peligros en el desierto, peligros en la mar, peligros entre falsos hermanos;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 27, 'En trabajo y fatiga, en muchas vigilias, en hambre y sed, en muchos ayunos, en frío y en desnudez;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 28, 'Sin otras cosas además, lo que sobre mí se agolpa cada día, la solicitud de todas las iglesias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 29, '¿Quién enferma, y yo no enfermo? ¿Quién se escandaliza, y yo no me quemo?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 30, 'Si es menester gloriarse, me gloriaré yo de lo que es de mi flaqueza.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 31, 'El Dios y Padre del Señor nuestro Jesucristo, que es bendito por siglos, sabe que no miento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 32, 'En Damasco, el gobernador de la provincia del rey Aretas guardaba la ciudad de los Damascenos para prenderme;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 11, 33, 'Y fuí descolgado del muro en un serón por una ventana, y escapé de sus manos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 1, 'CIERTO no me es conveniente gloriarme; mas vendré á las visiones y á las revelaciones del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 2, 'Conozco á un hombre en Cristo, que hace catorce años (si en el cuerpo, no lo sé; si fuera del cuerpo, no lo sé: Dios lo sabe) fué arrebatado hasta el tercer cielo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 3, 'Y conozco tal hombre, (si en el cuerpo, ó fuera del cuerpo, no lo sé: Dios lo sabe,)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 4, 'Que fué arrebatado al paraíso, donde oyó palabras secretas que el hombre no puede decir.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 5, 'De este tal me gloriaré, mas de mí mismo nada me gloriaré, sino en mis flaquezas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 6, 'Por lo cual si quisiere gloriarme, no seré insensato: porque diré verdad: empero lo dejo, porque nadie piense de mí más de lo que en mí ve, ú oye de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 7, 'Y porque la grandeza de las revelaciones no me levante descomedidamente, me es dado un aguijón en mi carne, un mensajero de Satanás que me abofetee, para que no me enaltezca sobremanera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 8, 'Por lo cual tres veces he rogado al Señor, que se quite de mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 9, 'Y me ha dicho: Bástate mi gracia; porque mi potencia en la flaqueza se perfecciona. Por tanto, de buena gana me gloriaré más bien en mis flaquezas, porque habite en mí la potencia de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 10, 'Por lo cual me gozo en las flaquezas, en afrentas, en necesidades, en persecuciones, en angustias por Cristo; porque cuando soy flaco, entonces soy poderoso.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 11, 'Heme hecho un necio en gloriarme: vosotros me constreñisteis; pues yo había de ser alabado de vosotros: porque en nada he sido menos que los sumos apóstoles, aunque soy nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 12, 'Con todo esto, las señales de apóstol han sido hechas entre vosotros en toda paciencia, en señales, y en prodigios, y en maravillas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 13, 'Porque ¿qué hay en que habéis sido menos que las otras iglesias, sino en que yo mismo no os he sido carga? Perdonadme esta injuria.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 14, 'He aquí estoy aparejado para ir á vosotros la tercera vez, y no os seré gravoso; porque no busco vuestras cosas, sino á vosotros: porque no han de atesorar los hijos para los padres sino los padres para los hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 15, 'Empero yo de muy buena gana despenderé y seré despendido por vuestras almas, aunque amándoos más, sea amado menos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 16, 'Mas sea así, yo no os he agravado: sino que, como soy astuto, os he tomado por engaño.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 17, '¿Acaso os he engañado por alguno de los que he enviado á vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 18, 'Rogué á Tito, y envié con él al hermano. ¿Os engañó quizá Tito? ¿no hemos procedido con el mismo espíritu y por las mismas pisadas?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 19, '¿Pensáis aún que nos excusamos con vosotros? Delante de Dios en Cristo hablamos: mas todo, muy amados, por vuestra edificación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 20, 'Porque temo que cuando llegare, no os halle tales como quiero, y yo sea hallado de vosotros cual no queréis; que haya entre vosotros contiendas, envidias, iras, disensiones, detracciones, murmuaciones, elaciones, bandos:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 12, 21, 'Que cuando volviere, me humille Dios entre vosotros, y haya de llorar por muchos de los que antes habrán pecado, y no se han arrepentido de la inmundicia y fornicación y deshonestidad que han cometido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 1, 'ESTA tercera vez voy á vosotros. En la boca de dos ó de tres testigos consistirá todo negocio.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 2, 'He dicho antes, y ahora digo otra vez como presente, y ahora ausente lo escribo á los que antes pecaron, y á todos los demás, que si voy otra vez, no perdonaré;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 3, 'Pues buscáis una prueba de Cristo que habla en mí, el cual no es flaco para con vosotros, antes es poderoso en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 4, 'Porque aunque fué crucificado por flaqueza, empero vive por potencia de Dios. Pues también nosotros somos flacos con él, mas viviremos con él por la potencia de Dios para con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 5, 'Examinaos á vosotros mismos si estáis en fe; probaos á vosotros mismos. ¿No os conocéis á vosotros mismos, que Jesucristo está en vosotros? si ya no sois reprobados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 6, 'Mas espero que conoceréis que nosotros no somos reprobados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 7, 'Y oramos á Dios que ninguna cosa mala hagáis; no para que nosotros seamos hallados aprobados, mas para que vosotros hagáis lo que es bueno, aunque nosotros seamos como reprobados.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 8, 'Porque ninguna cosas podemos contra la verdad, sino por la verdad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 9, 'Por lo cual nos gozamos que seamos nosotros flacos, y que vosotros estéis fuertes; y aun deseamos vuestra perfección.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 10, 'Por tanto os escribo esto ausente, por no tratar presente con dureza, conforme á la potestad que el Señor me ha dado para edificación, y no para destrucción.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 11, 'Resta, hermanos, que tengáis gozo, seáis perfectos, tengáis consolación, sintáis una misma cosa, tengáis paz; y el Dios de paz y de caridad será con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 12, 'Saludaos los unos á los otros con ósculo santo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 13, '(13-12) Todos los santos os saludan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('2CO', '2 Corintios', 13, 14, '(13-13) La gracia del Señor Jesucristo, y el amor de Dios, y la participación del Espíritu Santo sea con vosotros todos. Amén. Epístola á los Corintios fué enviada de Filipos de Macedonia con Tito y Lucas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 1, 'PABLO, apóstol, (no de los hombres ni por hombre, mas por Jesucristo y por Dios el Padre, que lo resucitó de los muertos),');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 2, 'Y todos los hermanos que están conmigo, á las iglesias de Galacia:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 3, 'Gracia sea á vosotros, y paz de Dios el Padre, y de nuestro Señor Jesucristo,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 4, 'El cual se dió á sí mismo por nuestros pecados para librarnos de este presente siglo malo, conforme á la voluntad de Dios y Padre nuestro;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 5, 'Al cual sea la gloria por siglos de siglos. Amén.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 6, 'Estoy maravillado de que tan pronto os hayáis traspasado del que os llamó á la gracia de Cristo, á otro evangelio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 7, 'No que hay otro, sino que hay algunos que os inquietan, y quieren pervertir el evangelio de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 8, 'Mas aun si nosotros ó un ángel del cielo os anunciare otro evangelio del que os hemos anunciado, sea anatema.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 9, 'Como antes hemos dicho, también ahora decimos otra vez: Si alguno os anunciare otro evangelio del que habéis recibido, sea anatema.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 10, 'Porque, ¿persuado yo ahora á hombres ó á Dios? ¿ó busco de agradar á hombres? Cierto, que si todavía agradara á los hombres, no sería siervo de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 11, 'Mas os hago saber, hermanos, que el evangelio que ha sido anunciado por mí, no es según hombre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 12, 'Pues ni yo lo recibí, ni lo aprendí de hombre, sino por revelación de Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 13, 'Porque ya habéis oído acerca de mi conducta otro tiempo en el Judaismo, que perseguía sobremanera la iglesia de Dios, y la destruía;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 14, 'Y aprovechaba en el Judaismo sobre muchos de mis iguales en mi nación, siendo muy más celador que todos de las tradiciones de mis padres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 15, 'Mas cuando plugo á Dios, que me apartó desde el vientre de mi madre, y me llamó por su gracia,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 16, 'Revelar á su Hijo en mí, para que le predicase entre los Gentiles, luego no conferí con carne y sangre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 17, 'Ni fuí á Jerusalem á los que eran apóstoles antes que yo; sino que me fuí á la Arabia, y volví de nuevo á Damasco.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 18, 'Depués, pasados tres años, fuí á Jerusalem á ver á Pedro, y estuve con él quince días.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 19, 'Mas á ningún otro de los apóstoles vi, sino á Jacobo el hermano del Señor.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 20, 'Y en esto que os escribo, he aquí delante de Dios, no miento.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 21, 'Después fuí á las partes de Siria y de Cilicia;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 22, 'Y no era conocido de vista á las iglesias de Judea, que eran en Cristo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 23, 'Solamente habían oído decir: Aquel que en otro tiempo nos perseguía, ahora anuncia la fe que en otro tiempo destruía.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 1, 24, 'Y glorificaban á Dios en mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 1, 'DESPUÉS, pasados catorce años, fuí otra vez á Jerusalem juntamente con Bernabé, tomando también conmigo á Tito.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 2, 'Empero fuí por revelación, y comuniquéles el evangelio que predico entre los Gentiles; mas particularmente á los que parecían ser algo, por no correr en vano, ó haber corrido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 3, 'Mas ni aun Tito, que estaba conmigo, siendo Griego, fué compelido á circuncidarse.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 4, 'Y eso por causa de los falsos hermanos, que se entraban secretamente para espiar nuestra libertad que tenemos en Cristo Jesús, para ponernos en servidumbre;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 5, 'A los cuales ni aun por una hora cedimos sujetándonos, para que la verdad del evangelio permaneciese con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 6, 'Empero de aquellos que parecían ser algo (cuáles hayan sido algún tiempo, no tengo que ver; Dios no acepta apariencia de hombre), á mí ciertamente los que parecían ser algo, nada me dieron.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 7, 'Antes por el contrario, como vieron que el evangelio de la incircuncisión me era encargado, como á Pedro el de la circuncisión,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 8, '(Porque el que hizo por Pedro para el apostolado de la circuncisión, hizo también por mí para con los Gentiles;)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 9, 'Y como vieron la gracia que me era dada, Jacobo y Cefas y Juan, que parecían ser las columnas, nos dieron las diestras de compañía á mí y á Bernabé, para que nosotros fuésemos á los Gentiles, y ellos á la circuncisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 10, 'Solamente nos pidieron que nos acordásemos de los pobres; lo mismo que fuí también solícito en hacer.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 11, 'Empero viniendo Pedro á Antioquía, le resistí en la cara, porque era de condenar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 12, 'Porque antes que viniesen unos de parte de Jacobo, comía con los Gentiles; mas después que vinieron, se retraía y apartaba, teniendo miedo de los que eran de la circuncisión.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 13, 'Y á su disimulación consentían también los otros Judíos; de tal manera que aun Bernabé fué también llevado de ellos en su simulación.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 14, 'Mas cuando vi que no andaban derechamente conforme á la verdad del evangelio, dije á Pedro delante de todos: Si tú, siendo Judío, vives como los Gentiles y no como Judío, ¿por qué constriñes á los Gentiles á judaizar?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 15, 'Nosotros Judíos naturales, y no pecadores de los Gentiles,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 16, 'Sabiendo que el hombre no es justificado por las obras de la ley, sino por la fe de Jesucristo, nosotros también hemos creído en Jesucristo, para que fuésemos justificados por la fe de Cristo, y no por las obras de la ley; por cuanto por las obras de la ley ninguna carne será justificada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 17, 'Y si buscando nosotros ser justificados en Cristo, también nosotros somos hallados pecadores, ¿es por eso Cristo ministro de pecado? En ninguna manera.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 18, 'Porque si las cosas que destruí, las mismas vuelvo á edificar, transgresor me hago.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 19, 'Porque yo por la ley soy muerto á la ley, para vivir á Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 20, 'Con Cristo estoy juntamente crucificado, y vivo, no ya yo, mas vive Cristo en mí: y lo que ahora vivo en la carne, lo vivo en la fe del Hijo de Dios, el cual me amó, y se entregó á sí mismo por mí.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 2, 21, 'No desecho la gracia de Dios: porque si por la ley fuese la justicia, entonces por demás murió Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 1, '¡OH Gálatas insensatos! ¿quién os fascinó, para no obedecer á la verdad, ante cuyos ojos Jesucristo fué ya descrito como crucificado entre vosotros?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 2, 'Esto solo quiero saber de vosotros: ¿Recibisteis el Espíritu por las obras de la ley, ó por el oir de la fe?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 3, '¿Tan necios sois? ¿habiendo comenzado por el Espíritu, ahora os perfeccionáis por la carne?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 4, '¿Tantas cosas habéis padecido en vano? si empero en vano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 5, 'Aquel, pues, que os daba el Espíritu, y obraba maravillas entre vosotros ¿hacíalo por las obras de la ley, ó por el oir de la fe?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 6, 'Como Abraham creyó á Dios, y le fué imputado á justicia.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 7, 'Sabéis por tanto, que los que son de fe, los tales son hijos de Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 8, 'Y viendo antes la Escritura que Dios por la fe había de justificar á los Gentiles, evangelizó antes á Abraham, diciendo: En ti serán benditas todas las naciones.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 9, 'Luego los de la fe son benditos con el creyente Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 10, 'Porque todos los que son de las obras de la ley, están bajo de maldición. Porque escrito está: Maldito todo aquel que no permaneciere en todas las cosas que están escritas en el libro de la ley, para hacerlas.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 11, 'Mas por cuanto por la ley ninguno se justifica para con Dios, queda manifiesto: Que el justo por la fe vivirá.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 12, 'La ley también no es de la fe; sino, El hombre que los hiciere, vivirá en ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 13, 'Cristo nos redimió de la maldición de la ley, hecho por nosotros maldición; (porque está escrito: Maldito cualquiera que es colgado en madero:)');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 14, 'Para que la bendición de Abraham fuese sobre los Gentiles en Cristo Jesús; para que por la fe recibamos la promesa del Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 15, 'Hermanos, hablo como hombre: Aunque un pacto sea de hombre, con todo, siendo confirmado, nadie lo cancela, ó le añade.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 16, 'A Abraham fueron hechas las promesas, y á su simiente. No dice: Y á las simientes, como de muchos; sino como de uno: Y á tu simiente, la cual es Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 17, 'Esto pues digo: Que el contrato confirmado de Dios para con Cristo, la ley que fué hecha cuatrocientos treinta años después, no lo abroga, para invalidar la promesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 18, 'Porque si la herencia es por la ley, ya no es por la promesa: empero Dios por la promesa hizo la donación á Abraham.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 19, '¿Pues de qué sirve la ley? Fué puesta por causa de las rebeliones, hasta que viniese la simiente á quien fué hecha la promesa, ordenada aquélla por los ángeles en la mano de un mediador.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 20, 'Y el mediador no es de uno, pero Dios es uno.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 21, '¿Luego la ley es contra las promesas de Dios? En ninguna manera: porque si la ley dada pudiera vivificar, la justicia fuera verdaderamente por la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 22, 'Mas encerró la Escritura todo bajo pecado, para que la promesa fuese dada á los creyentes por la fe de Jesucristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 23, 'Empero antes que viniese la fe, estábamos guardados bajo la ley, encerrados para aquella fe que había de ser descubierta.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 24, 'De manera que la ley nuestro ayo fué para llevarnos á Cristo, para que fuésemos justificados por la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 25, 'Mas venida la fe, ya no estamos bajo ayo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 26, 'Porque todos sois hijos de Dios por la fe en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 27, 'Porque todos los que habéis sido bautizados en Cristo, de Cristo estáis vestidos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 28, 'No hay Judío, ni Griego; no hay siervo, ni libre; no hay varón, ni hembra: porque todos vosotros sois uno en Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 3, 29, 'Y si vosotros sois de Cristo, ciertamente la simiente de Abraham sois, y conforme á la promesa los herederos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 1, 'TAMBIÉN digo: Entre tanto que el heredero es niño, en nada difiere del siervo, aunque es señor de todo;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 2, 'Mas está debajo de tutores y curadores hasta el tiempo señalado por el padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 3, 'Así también nosotros, cuando éramos niños, éramos siervos bajo los rudimentos del mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 4, 'Mas venido el cumplimiento del tiempo, Dios envió su Hijo, hecho de mujer, hecho súbdito á la ley,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 5, 'Para que redimiese á los que estaban debajo de la ley, á fin de que recibiésemos la adopción de hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 6, 'Y por cuanto sois hijos, Dios envió el Espíritu de su Hijo en vuestros corazones, el cual clama: Abba, Padre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 7, 'Así que ya no eres más siervo, sino hijo, y si hijo, también heredero de Dios por Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 8, 'Antes, en otro tiempo, no conociendo á Dios, servíais á los que por naturaleza no son dioses:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 9, 'Mas ahora, habiendo conocido á Dios, ó más bien, siendo conocidos de Dios, ¿cómo os volvéis de nuevo á los flacos y pobres rudimentos, en los cuales queréis volver á servir?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 10, 'Guardáis los días, y los meses, y los tiempos, y los años.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 11, 'Temo de vosotros, que no haya trabajado en vano en vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 12, 'Hermanos, os ruego, sed como yo, porque yo soy como vosotros: ningún agravio me habéis hecho.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 13, 'Que vosotros sabéis que por flaqueza de carne os anuncié el evangelio al principio:');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 14, 'Y no desechasteis ni menospreciasteis mi tentación que estaba en mi carne: antes me recibisteis como á un ángel de Dios, como á Cristo Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 15, '¿Dónde está pues vuestra bienaventuranza? porque yo os doy testimonio que si se pudiera hacer, os hubierais sacado vuestros ojos para dármelos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 16, '¿Heme pues hecho vuestro enemigo, diciéndoos la verdad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 17, 'Tienen celos de vosotros, pero no bien: antes os quieren echar fuera para que vosotros los celéis á ellos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 18, 'Bueno es ser celosos en bien siempre; y no solamente cuando estoy presente con vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 19, 'Hijitos míos, que vuelvo otra vez á estar de parto de vosotros, hasta que Cristo sea formado en vosotros;');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 20, 'Querría cierto estar ahora con vosotros, y mudar mi voz; porque estoy perplejo en cuanto á vosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 21, 'Decidme, los que queréis estar debajo de la ley, ¿no habéis oído la ley?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 22, 'Porque escrito está que Abraham tuvo dos hijos; uno de la sierva, el otro de la libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 23, 'Mas el de la sierva nació según la carne; pero el de la libre nació por la promesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 24, 'Las cuales cosas son dichas por alegoría: porque estas mujeres son los dos pactos; el uno ciertamente del monte Sinaí, el cual engendró para servidumbre, que es Agar.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 25, 'Porque Agar ó Sinaí es un monte de Arabia, el cual es conjunto á la que ahora es Jerusalem, la cual sirve con sus hijos.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 26, 'Mas la Jerusalem de arriba libre es; la cual es la madre de todos nosotros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 27, 'Porque está escrito: Alégrate, estéril, que no pares: Prorrumpe y clama, la que no estás de parto; Porque más son los hijos de la dejada, que de la que tiene marido.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 28, 'Así que, hermanos, nosotros como Isaac somos hijos de la promesa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 29, 'Empero como entonces el que era engendrado según la carne, perseguía al que había nacido según el Espíritu, así también ahora.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 30, 'Mas ¿qué dice la Escritura? Echa fuera á la sierva y á su hijo; porque no será heredero el hijo de la sierva con el hijo de la libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 4, 31, 'De manera, hermanos, que no somos hijos de la sierva, mas de la libre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 1, 'ESTAD, pues, firmes en la libertad con que Cristo nos hizo libres, y no volváis otra vez á ser presos en el yugo de servidumbre.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 2, 'He aquí yo Pablo os digo, que si os circuncidareis, Cristo no os aprovechará nada.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 3, 'Y otra vez vuelvo á protestar á todo hombre que se circuncidare, que está obligado á hacer toda la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 4, 'Vacíos sois de Cristo los que por la ley os justificáis; de la gracia habéis caído.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 5, 'Porque nosotros por el Espíritu esperamos la esperanza de la justicia por la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 6, 'Porque en Cristo Jesús ni la circuncisión vale algo, ni la incircuncisión; sino la fe que obra por la caridad.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 7, 'Vosotros corríais bien: ¿quién os embarazó para no obedecer á la verdad?');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 8, 'Esta persuasión no es de aquel que os llama.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 9, 'Un poco de levadura leuda toda la masa.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 10, 'Yo confío de vosotros en el Señor, que ninguna otra cosa sentiréis: mas el que os inquieta, llevará el juicio, quienquiera que él sea.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 11, 'Y yo, hermanos, si aun predico la circuncisión, ¿por qué padezco pesecución todavía? pues que quitado es el escándalo de la cruz.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 12, 'Ojalá fuesen también cortados los que os inquietan.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 13, 'Porque vosotros, hermanos, á libertad habéis sido llamados; solamente que no uséis la libertad como ocasión á la carne, sino servíos por amor los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 14, 'Porque toda la ley en aquesta sola palabra se cumple: Amarás á tu prójimo como á ti mismo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 15, 'Y si os mordéis y os coméis los unos á los otros, mirad que también no os consumáis los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 16, 'Digo pues: Andad en el Espíritu, y no satisfagáis la concupiscencia de la carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 17, 'Porque la carne codicia contra el Espíritu, y el Espíritu contra la carne: y estas cosas se oponen la una á la otra, para que no hagáis lo que quisieres.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 18, 'Mas si sois guiados del Espíritu, no estáis bajo la ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 19, 'Y manifiestas son las obras de la carne, que son: adulterio, fornicación, inmundicia, disolución,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 20, 'Idolatría, hechicerías, enemistades, pleitos, celos, iras, contiendas, disensiones, herejías,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 21, 'Envidias, homicidios, borracheras, banqueteos, y cosas semejantes á éstas: de las cuales os denuncio, como ya os he anunciado, que los que hacen tales cosas no heredarán el reino de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 22, 'Mas el fruto del Espíritu es: caridad, gozo, paz, tolerancia, benignidad, bondad, fe,');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 23, 'Mansedumbre, templanza: contra tales cosas no hay ley.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 24, 'Porque los que son de Cristo, han crucificado la carne con los afectos y concupiscencias.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 25, 'Si vivimos en el Espíritu, andemos también en el Espíritu.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 5, 26, 'No seamos codiciosos de vana gloria, irritando los unos á los otros, envidiándose los unos á los otros.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 1, 'HERMANOS, si alguno fuere tomado en alguna falta, vosotros que sois espirituales, restaurad al tal con el espíritu de mansedumbre; considerándote á ti mismo, porque tú no seas también tentado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 2, 'Sobrellevad los unos las cargas de los otros; y cumplid así la ley de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 3, 'Porque el que estima de sí que es algo, no siendo nada, á sí mismo se engaña.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 4, 'Así que cada uno examine su obra, y entonces tendrá gloria sólo respecto de sí mismo, y no en otro.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 5, 'Porque cada cual llevará su carga.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 6, 'Y el que es enseñado en la palabra, comunique en todos los bienes al que lo instruye.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 7, 'No os engañeis: Dios no puede ser burlado: que todo lo que el hombre sembrare, eso también segará.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 8, 'Porque el que siembra para su carne, de la carne segará corrupción; mas el que siembra para el Espíritu, del Espíritu segará vida eterna.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 9, 'No nos cansemos, pues, de hacer bien; que á su tiempo segaremos, si no hubiéremos desmayado.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 10, 'Así que, entre tanto que tenemos tiempo, hagamos bien á todos, y mayormente á los domésticos de la fe.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 11, 'Mirad en cuán grandes letras os he escrito de mi mano.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 12, 'Todos los que quieren agradar en al carne, éstos os constriñen á que os circuncidéis, solamente por no padecer persecución por la cruz de Cristo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 13, 'Porque ni aun los mismos que se circuncidan guardan la ley; sino que quieren que vosotros seáis circuncidados, para gloriarse en vuestra carne.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 14, 'Mas lejos esté de mí gloriarme, sino en la cruz de nuestro Señor Jesucristo, por el cual el mundo me es crucificado á mí, y yo al mundo.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 15, 'Porque en Cristo Jesús, ni la circuncisión vale nada, ni la incircuncisión, sino la nueva criatura.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 16, 'Y todos los que anduvieren conforme á esta regla, paz sobre ellos, y misericordia, y sobre el Israel de Dios.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 17, 'De aquí adelante nadie me sea molesto; porque yo traigo en mi cuerpo las marcas del Señor Jesús.');
INSERT INTO bible_verses (book_id, book_name, chapter, verse, text) VALUES ('GAL', 'Gálatas', 6, 18, 'Hermanos, la gracia de nuestro Señor Jesucristo sea con vuestro espíritu. Amén.');
